insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 1, 'Dua Kalimah Syahadah', 'Dua Kalimah Syahadah terdiri daripada Syahadah pertama dan Syahadah kedua. Syahadah kedua ialah pengakuan bahawa Nabi Muhammad SAW adalah:', 'mcq', array['Malaikat Allah', 'Rasul Allah', 'Sahabat Allah', 'Wali Allah'], 'Rasul Allah', 'Syahadah kedua berbunyi "Wa asyhadu anna Muhammadar Rasulullah" yang bermaksud bersaksi bahawa Nabi Muhammad SAW ialah pesuruh (Rasul) Allah. Berdasarkan Rukun Islam yang pertama.', 'standard', array['syahadah', 'rasul', 'rukun_islam']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 1, 'Dua Kalimah Syahadah', 'Dua Kalimah Syahadah ialah rukun Islam yang kedua.', 'true_false', null, 'Salah', 'Dua Kalimah Syahadah ialah rukun Islam yang PERTAMA, bukan kedua. Berdasarkan hadis riwayat Bukhari dan Muslim tentang Rukun Islam yang lima.', 'standard', array['syahadah', 'rukun_islam']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 2, 'Rukun Islam & Rukun Iman', 'Rukun Islam yang kedua ialah:', 'mcq', array['Berpuasa', 'Mengerjakan solat', 'Menunaikan zakat', 'Mengerjakan haji'], 'Mengerjakan solat', 'Rukun Islam yang kedua ialah mendirikan solat lima waktu sehari semalam. Berdasarkan hadis riwayat Bukhari dan Muslim.', 'easy', array['rukun_islam', 'solat']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 2, 'Rukun Islam & Rukun Iman', 'Beriman kepada malaikat ialah salah satu Rukun Iman.', 'true_false', null, 'Benar', 'Beriman kepada malaikat ialah Rukun Iman yang kedua. Berdasarkan Surah Al-Baqarah ayat 285.', 'easy', array['rukun_iman', 'malaikat']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 2, 'Rukun Islam & Rukun Iman', 'Rukun Islam yang kelima ialah mengerjakan ____ bagi yang mampu.', 'fill_blank', null, 'haji', 'Rukun Islam yang kelima ialah menunaikan haji ke Baitullah bagi orang yang berkemampuan. Berdasarkan hadis riwayat Bukhari dan Muslim.', 'easy', array['rukun_islam', 'haji']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 2, 'Rukun Islam & Rukun Iman', 'Manakah antara berikut yang BUKAN termasuk dalam Rukun Iman?', 'mcq', array['Beriman kepada Allah', 'Beriman kepada Malaikat', 'Beriman kepada Solat', 'Beriman kepada Hari Akhirat'], 'Beriman kepada Solat', 'Solat ialah Rukun Islam, bukan Rukun Iman. Rukun Iman yang enam ialah beriman kepada Allah, Malaikat, Kitab, Rasul, Hari Akhirat dan Qada'' serta Qadar. Berdasarkan hadis Jibril riwayat Muslim.', 'standard', array['rukun_iman', 'rukun_islam']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 2, 'Rukun Islam & Rukun Iman', 'Ali berkata: "Saya beriman kepada Allah, tetapi saya tidak percaya adanya malaikat." Adakah Ali mengamalkan Rukun Iman dengan sempurna?', 'mcq', array['Ya, kerana beriman kepada Allah sudah cukup', 'Tidak, kerana perlu beriman kepada semua enam perkara', 'Ya, kerana malaikat tidak penting', 'Tidak, kerana beriman kepada Allah bukan Rukun Iman'], 'Tidak, kerana perlu beriman kepada semua enam perkara', 'Rukun Iman mempunyai 6 perkara dan semuanya wajib dipercayai. Tidak boleh memilih untuk percaya sebahagian sahaja. Berdasarkan hadis Jibril riwayat Muslim.', 'kbat', array['rukun_iman', 'analisis']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 3, 'Bersuci & Istinjak', 'Air yang paling baik untuk bersuci ialah:', 'mcq', array['Air sirap', 'Air mutlak', 'Air kopi', 'Air berwarna'], 'Air mutlak', 'Air mutlak ialah air bersih yang tidak bercampur dengan bahan lain. Air ini suci dan menyucikan. Berdasarkan kitab fiqh asas Mazhab Syafie.', 'easy', array['bersuci', 'air_mutlak']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 3, 'Bersuci & Istinjak', 'Darah yang keluar daripada luka ialah najis.', 'true_false', null, 'Benar', 'Darah termasuk dalam najis mutawasitah (sederhana). Ia perlu dibersihkan dengan air sehingga hilang sifatnya (warna, bau, rasa). Berdasarkan hukum fiqh Mazhab Syafie.', 'easy', array['najis', 'bersuci']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 3, 'Bersuci & Istinjak', 'Islam mengajar kita supaya sentiasa menjaga ____ badan dan pakaian.', 'fill_blank', null, 'kebersihan', 'Islam amat mementingkan kebersihan. Rasulullah SAW bersabda: "Kebersihan itu sebahagian daripada iman." Hadis riwayat Muslim.', 'easy', array['bersuci', 'kebersihan']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 3, 'Bersuci & Istinjak', 'Selepas buang air kecil, kita perlu membersihkan diri. Perbuatan ini disebut:', 'mcq', array['Wuduk', 'Istinjak', 'Mandi wajib', 'Tayamum'], 'Istinjak', 'Istinjak ialah membersihkan najis yang keluar dari qubul (kemaluan hadapan) atau dubur (kemaluan belakang) menggunakan air atau batu. Berdasarkan hukum fiqh Mazhab Syafie.', 'standard', array['istinjak', 'bersuci']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 3, 'Bersuci & Istinjak', 'Kita boleh menyentuh Al-Quran walaupun badan kita bernajis.', 'true_false', null, 'Salah', 'Tidak boleh menyentuh Al-Quran dalam keadaan tidak suci (berhadas atau bernajis). Berdasarkan Surah Al-Waqiah ayat 79: "Tidak menyentuhnya kecuali orang-orang yang disucikan."', 'standard', array['bersuci', 'al_quran']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 4, 'Wuduk & Tayamum', 'Perkara pertama yang kita basuh semasa mengambil wuduk ialah:', 'mcq', array['Kaki', 'Tangan', 'Muka', 'Kepala'], 'Muka', 'Fardu wuduk yang pertama ialah membasuh muka. Berdasarkan Surah Al-Maidah ayat 6 yang menyebut urutan wuduk.', 'easy', array['wuduk', 'fardu_wuduk']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 4, 'Wuduk & Tayamum', 'Jika tiada air, kita boleh bertayamum menggunakan ____ yang bersih.', 'fill_blank', null, 'tanah', 'Tayamum ialah bersuci menggunakan tanah atau debu yang bersih apabila tiada air. Berdasarkan Surah An-Nisa'' ayat 43.', 'easy', array['tayamum', 'wuduk']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 4, 'Wuduk & Tayamum', 'Wuduk akan batal jika kita tertidur.', 'true_false', null, 'Benar', 'Tidur yang nyenyak (tidak dalam keadaan duduk yang teguh) membatalkan wuduk. Berdasarkan hadis riwayat Abu Daud dan hukum fiqh Mazhab Syafie.', 'easy', array['wuduk', 'batal_wuduk']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 4, 'Wuduk & Tayamum', 'Manakah antara berikut yang membatalkan wuduk?', 'mcq', array['Makan nasi', 'Minum air', 'Buang angin', 'Bercakap'], 'Buang angin', 'Buang angin (kentut) termasuk perkara yang membatalkan wuduk kerana ia merupakan sesuatu yang keluar dari dubur. Berdasarkan hadis riwayat Bukhari dan Muslim.', 'standard', array['wuduk', 'batal_wuduk']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 4, 'Wuduk & Tayamum', 'Semasa wuduk, selepas membasuh muka, kita membasuh kedua-dua ____ hingga ke siku.', 'fill_blank', null, 'tangan', 'Fardu wuduk yang kedua ialah membasuh kedua-dua tangan hingga ke siku. Berdasarkan Surah Al-Maidah ayat 6.', 'standard', array['wuduk', 'fardu_wuduk']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 5, 'Mandi Wajib', 'Semasa mandi wajib, kita perlu memastikan air mengalir ke:', 'mcq', array['Tangan sahaja', 'Muka sahaja', 'Seluruh badan', 'Kaki sahaja'], 'Seluruh badan', 'Fardu mandi wajib yang utama ialah meratakan air ke seluruh badan tanpa ada bahagian yang tertinggal. Berdasarkan hukum fiqh Mazhab Syafie.', 'easy', array['mandi_wajib', 'fardu']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 5, 'Mandi Wajib', 'Niat ialah perkara penting semasa mandi wajib.', 'true_false', null, 'Benar', 'Niat ialah fardu pertama dalam mandi wajib. Berdasarkan hadis riwayat Bukhari dan Muslim: "Sesungguhnya setiap amalan itu bergantung kepada niat."', 'easy', array['mandi_wajib', 'niat']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 5, 'Mandi Wajib', 'Sebelum mandi wajib, kita hendaklah membaca ____ terlebih dahulu.', 'fill_blank', null, 'Bismillah', 'Sunat membaca Bismillah sebelum memulakan mandi wajib. Berdasarkan hadis riwayat Abu Daud.', 'easy', array['mandi_wajib', 'sunat']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 5, 'Mandi Wajib', 'Manakah antara berikut yang merupakan fardu mandi wajib?', 'mcq', array['Berniat', 'Berwuduk', 'Bersikat rambut', 'Bercermin'], 'Berniat', 'Niat ialah fardu pertama mandi wajib. Mandi wajib mempunyai dua fardu iaitu berniat dan meratakan air ke seluruh badan. Berdasarkan hukum fiqh Mazhab Syafie.', 'standard', array['mandi_wajib', 'fardu']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 5, 'Mandi Wajib', 'Ahmad mandi wajib tetapi tidak berniat. Mandi wajibnya sah.', 'true_false', null, 'Salah', 'Mandi wajib tanpa niat adalah tidak sah kerana niat ialah salah satu fardu mandi wajib. Berdasarkan hadis riwayat Bukhari dan Muslim: "Sesungguhnya setiap amalan itu bergantung kepada niat."', 'kbat', array['mandi_wajib', 'niat', 'analisis']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 6, 'Solat Fardu & Toma''ninah', 'Solat Subuh mempunyai 2 rakaat.', 'true_false', null, 'Benar', 'Solat Subuh terdiri daripada 2 rakaat dan dikerjakan pada waktu fajar (sebelum terbit matahari). Berdasarkan hadis riwayat Bukhari dan Muslim.', 'easy', array['solat_fardu', 'rakaat', 'subuh']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 6, 'Solat Fardu & Toma''ninah', 'Solat fardu yang mempunyai 4 rakaat dan dikerjakan pada waktu tengah hari ialah:', 'mcq', array['Solat Subuh', 'Solat Zohor', 'Solat Maghrib', 'Solat Isyak'], 'Solat Zohor', 'Solat Zohor dikerjakan selepas gelincir matahari (tengah hari) dan mempunyai 4 rakaat. Berdasarkan hadis riwayat Bukhari dan Muslim.', 'easy', array['solat_fardu', 'zohor', 'rakaat']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 6, 'Solat Fardu & Toma''ninah', 'Solat Maghrib dikerjakan selepas ____ matahari.', 'fill_blank', null, 'terbenam', 'Waktu Solat Maghrib bermula selepas terbenam matahari. Solat Maghrib mempunyai 3 rakaat. Berdasarkan hadis riwayat Muslim.', 'easy', array['solat_fardu', 'maghrib', 'waktu_solat']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 6, 'Solat Fardu & Toma''ninah', 'Berapakah jumlah rakaat Solat Isyak?', 'mcq', array['2 rakaat', '3 rakaat', '4 rakaat', '5 rakaat'], '4 rakaat', 'Solat Isyak mempunyai 4 rakaat dan dikerjakan selepas hilang mega merah di ufuk barat. Berdasarkan hadis riwayat Bukhari dan Muslim.', 'standard', array['solat_fardu', 'isyak', 'rakaat']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 6, 'Solat Fardu & Toma''ninah', 'Solat Maghrib mempunyai 4 rakaat seperti Solat Zohor.', 'true_false', null, 'Salah', 'Solat Maghrib mempunyai 3 rakaat, bukan 4. Solat Zohor, Asar dan Isyak masing-masing mempunyai 4 rakaat. Berdasarkan hadis riwayat Bukhari dan Muslim.', 'standard', array['solat_fardu', 'maghrib', 'rakaat']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 7, 'Solat Berjemaah & Masbuk Muafik', 'Solat berjemaah mendapat ganjaran berapa kali ganda berbanding solat bersendirian?', 'mcq', array['5 kali ganda', '10 kali ganda', '27 kali ganda', '100 kali ganda'], '27 kali ganda', 'Rasulullah SAW bersabda bahawa solat berjemaah lebih utama daripada solat bersendirian sebanyak 27 darjat. Hadis riwayat Bukhari dan Muslim.', 'easy', array['solat_berjemaah', 'ganjaran']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 7, 'Solat Berjemaah & Masbuk Muafik', 'Orang yang mengikut imam dalam solat berjemaah dipanggil ____.', 'fill_blank', null, 'makmum', 'Makmum ialah orang yang solat di belakang imam dan mengikut setiap pergerakan imam. Berdasarkan hukum fiqh Mazhab Syafie.', 'easy', array['solat_berjemaah', 'makmum']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 7, 'Solat Berjemaah & Masbuk Muafik', 'Dalam solat berjemaah, makmum perlu mengikut pergerakan imam.', 'true_false', null, 'Benar', 'Makmum wajib mengikut pergerakan imam dan tidak boleh mendahului imam. Rasulullah SAW bersabda: "Sesungguhnya imam itu dijadikan untuk diikuti." Hadis riwayat Bukhari dan Muslim.', 'easy', array['solat_berjemaah', 'makmum', 'imam']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 7, 'Solat Berjemaah & Masbuk Muafik', 'Apabila makmum datang lewat dan terlepas satu rakaat, dia dipanggil:', 'mcq', array['Imam', 'Muafik', 'Masbuk', 'Munfarid'], 'Masbuk', 'Masbuk ialah makmum yang tidak sempat mengikut imam dari awal solat dan tertinggal sekurang-kurangnya satu rakaat. Berdasarkan hukum fiqh Mazhab Syafie.', 'standard', array['solat_berjemaah', 'masbuk']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 7, 'Solat Berjemaah & Masbuk Muafik', 'Abu sampai di masjid ketika imam sedang sujud pada rakaat kedua Solat Zohor. Apa yang perlu Abu buat?', 'mcq', array['Tunggu imam bangun berdiri baru takbiratul ihram', 'Terus takbiratul ihram dan ikut imam', 'Solat sendiri sahaja', 'Balik rumah dan solat di rumah'], 'Terus takbiratul ihram dan ikut imam', 'Makmum yang datang lewat (masbuk) hendaklah terus bertakbiratul ihram dan mengikut imam dalam apa jua keadaan imam berada. Berdasarkan hadis riwayat Bukhari: "Apa yang kamu dapati (bersama imam), maka solatlah."', 'kbat', array['solat_berjemaah', 'masbuk', 'analisis']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 8, 'Puasa Ramadan', 'Kita berbuka puasa apabila:', 'mcq', array['Waktu Zohor masuk', 'Matahari terbenam', 'Waktu Asar masuk', 'Matahari terbit'], 'Matahari terbenam', 'Puasa bermula dari terbit fajar hingga terbenam matahari. Kita berbuka apabila masuk waktu Maghrib (matahari terbenam). Berdasarkan Surah Al-Baqarah ayat 187.', 'easy', array['puasa', 'berbuka']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 8, 'Puasa Ramadan', 'Kita makan sahur sebelum waktu ____ masuk.', 'fill_blank', null, 'Subuh', 'Sahur ialah makan pada waktu sebelum masuk waktu Subuh (terbit fajar). Rasulullah SAW menggalakkan umatnya bersahur. Hadis riwayat Bukhari dan Muslim.', 'easy', array['puasa', 'sahur']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 8, 'Puasa Ramadan', 'Makan dan minum dengan sengaja semasa berpuasa membatalkan puasa.', 'true_false', null, 'Benar', 'Makan dan minum dengan sengaja pada siang hari bulan Ramadan membatalkan puasa. Berdasarkan Surah Al-Baqarah ayat 187 dan ijmak ulama.', 'easy', array['puasa', 'batal_puasa']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 8, 'Puasa Ramadan', 'Manakah antara berikut yang TIDAK membatalkan puasa?', 'mcq', array['Makan nasi', 'Minum air', 'Berkumur semasa berwuduk', 'Makan gula-gula'], 'Berkumur semasa berwuduk', 'Berkumur semasa berwuduk tidak membatalkan puasa asalkan air tidak masuk ke dalam perut dengan sengaja. Berdasarkan hukum fiqh Mazhab Syafie.', 'standard', array['puasa', 'batal_puasa']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 8, 'Puasa Ramadan', 'Orang yang sakit teruk dibenarkan untuk tidak berpuasa dan menggantikannya pada hari lain.', 'true_false', null, 'Benar', 'Orang yang sakit dibenarkan tidak berpuasa dan wajib mengqadakan (menggantikan) puasa pada hari lain apabila sihat. Berdasarkan Surah Al-Baqarah ayat 184.', 'standard', array['puasa', 'uzur']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 9, 'Adab & Akhlak Islamiah', 'Apabila bertemu kawan, kita hendaklah memberi:', 'mcq', array['Salam', 'Wang', 'Makanan', 'Hadiah'], 'Salam', 'Rasulullah SAW menggalakkan umat Islam memberi salam apabila bertemu sesama Muslim. Hadis riwayat Muslim: "Kamu tidak akan masuk syurga sehingga kamu beriman, dan kamu tidak beriman sehingga kamu saling menyayangi."', 'easy', array['adab', 'salam']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 9, 'Adab & Akhlak Islamiah', 'Kita hendaklah makan dan minum menggunakan tangan kanan.', 'true_false', null, 'Benar', 'Rasulullah SAW bersabda: "Apabila seseorang kamu makan, hendaklah makan dengan tangan kanan." Hadis riwayat Muslim.', 'easy', array['adab', 'makan']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 9, 'Adab & Akhlak Islamiah', 'Sebelum makan, kita hendaklah membaca doa dan mengucapkan ____.', 'fill_blank', null, 'Bismillah', 'Rasulullah SAW mengajar kita membaca Bismillah sebelum makan. Hadis riwayat Bukhari dan Muslim.', 'easy', array['adab', 'makan', 'doa']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 9, 'Adab & Akhlak Islamiah', 'Apabila kita bersin, kita hendaklah mengucapkan:', 'mcq', array['Assalamualaikum', 'Alhamdulillah', 'Subhanallah', 'Astaghfirullah'], 'Alhamdulillah', 'Rasulullah SAW mengajar bahawa apabila bersin, hendaklah mengucap Alhamdulillah. Dan orang yang mendengar hendaklah menjawab Yarhamukallah. Hadis riwayat Bukhari.', 'standard', array['adab', 'bersin', 'doa']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 9, 'Adab & Akhlak Islamiah', 'Siti melihat kawannya sedang bersedih di sekolah. Apa yang patut Siti buat sebagai seorang Muslim yang berakhlak mulia?', 'mcq', array['Mengejek kawannya', 'Berpura-pura tidak nampak', 'Bertanya khabar dan menghiburkannya', 'Memberitahu kawan-kawan lain'], 'Bertanya khabar dan menghiburkannya', 'Islam mengajar kita supaya saling membantu dan mengambil berat tentang orang lain. Rasulullah SAW bersabda: "Perumpamaan orang-orang beriman dalam kasih sayang umpama satu jasad." Hadis riwayat Muslim.', 'kbat', array['adab', 'akhlak', 'tolong_menolong']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 10, 'Sirah Nabawiyah', 'Ibu Nabi Muhammad SAW bernama:', 'mcq', array['Khadijah', 'Aminah', 'Fatimah', 'Aisyah'], 'Aminah', 'Ibu Nabi Muhammad SAW ialah Aminah binti Wahab. Baginda dilahirkan di Makkah pada tahun Gajah. Berdasarkan kitab sirah Nabawiyah.', 'easy', array['sirah', 'keluarga_nabi']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 10, 'Sirah Nabawiyah', 'Datuk Nabi Muhammad SAW yang menjaga baginda selepas ibunya meninggal ialah Abdul ____.', 'fill_blank', null, 'Muttalib', 'Abdul Muttalib ialah datuk Nabi Muhammad SAW yang menjaga baginda selepas kewafatan ibunya Aminah. Berdasarkan kitab sirah Nabawiyah.', 'easy', array['sirah', 'keluarga_nabi']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 10, 'Sirah Nabawiyah', 'Nabi Muhammad SAW ialah nabi dan rasul yang terakhir.', 'true_false', null, 'Benar', 'Nabi Muhammad SAW ialah penutup segala nabi dan rasul (Khatamun Nabiyyin). Berdasarkan Surah Al-Ahzab ayat 40.', 'easy', array['sirah', 'khatam_nabi']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 10, 'Sirah Nabawiyah', 'Nabi Muhammad SAW berhijrah dari Makkah ke:', 'mcq', array['Mesir', 'Madinah', 'Taif', 'Habsyah'], 'Madinah', 'Nabi Muhammad SAW berhijrah dari Makkah ke Madinah atas perintah Allah SWT untuk meneruskan dakwah Islam. Peristiwa ini menjadi permulaan kalendar Hijriah. Berdasarkan kitab sirah Nabawiyah.', 'standard', array['sirah', 'hijrah']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t1', 10, 'Sirah Nabawiyah', 'Nabi Muhammad SAW menerima wahyu pertama di Gua ____.', 'fill_blank', null, 'Hira''', 'Nabi Muhammad SAW menerima wahyu pertama (Surah Al-Alaq ayat 1-5) melalui malaikat Jibril di Gua Hira'', Jabal Nur. Berdasarkan hadis riwayat Bukhari dan Muslim.', 'standard', array['sirah', 'wahyu', 'gua_hira']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 1, 'Dua Kalimah Syahadah', 'Apakah syarat pertama bagi sahnya pengucapan Dua Kalimah Syahadah?', 'mcq', array['Mengucapkan dengan suara yang kuat', 'Mengetahui makna lafaz syahadah yang diucapkan', 'Mengucapkan di dalam masjid', 'Mengucapkan di hadapan imam'], 'Mengetahui makna lafaz syahadah yang diucapkan', 'Berdasarkan ilmu tauhid, syarat pertama syahadah ialah al-''Ilmu iaitu mengetahui makna kalimah yang diucapkan. Tanpa kefahaman, pengucapan tidak dikira sah. (Rujukan: Kitab Ummul Barahin)', 'standard', array['syahadah', 'syarat_syahadah', 'tauhid']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 1, 'Dua Kalimah Syahadah', 'Dua Kalimah Syahadah mengandungi dua bahagian. Bahagian pertama ialah pengakuan bahawa tiada Tuhan selain Allah. Apakah maksud bahagian kedua?', 'mcq', array['Pengakuan bahawa malaikat adalah utusan Allah', 'Pengakuan bahawa Nabi Muhammad SAW adalah Rasul Allah', 'Pengakuan bahawa Al-Quran adalah kitab terakhir', 'Pengakuan bahawa hari kiamat pasti berlaku'], 'Pengakuan bahawa Nabi Muhammad SAW adalah Rasul Allah', 'Bahagian kedua Dua Kalimah Syahadah ialah "Wa asyhadu anna Muhammadar Rasulullah" yang bermaksud pengakuan bahawa Nabi Muhammad SAW adalah pesuruh Allah. (Rujukan: Surah Al-Fath 48:29)', 'easy', array['syahadah', 'makna_syahadah', 'rasulullah']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 2, 'Rukun Islam & Rukun Iman', 'Berapakah jumlah Rukun Iman dan apakah rukun yang terakhir?', 'mcq', array['5 rukun - beriman kepada hari akhirat', '6 rukun - beriman kepada Qada dan Qadar', '6 rukun - beriman kepada hari akhirat', '5 rukun - beriman kepada Qada dan Qadar'], '6 rukun - beriman kepada Qada dan Qadar', 'Rukun Iman ada 6 perkara dan yang terakhir ialah beriman kepada Qada dan Qadar. Berdasarkan hadis riwayat Muslim yang masyhur tentang Jibril bertanya kepada Nabi SAW tentang iman.', 'easy', array['rukun_iman', 'qada_qadar', 'asas_iman']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 2, 'Rukun Islam & Rukun Iman', 'Apakah kesan jika seseorang Muslim dengan sengaja meninggalkan solat fardu tanpa keuzuran?', 'mcq', array['Solatnya digantikan oleh pahala puasa', 'Dia masih dianggap Muslim yang sempurna', 'Dia berdosa besar kerana solat adalah tiang agama', 'Dia hanya perlu membayar fidyah'], 'Dia berdosa besar kerana solat adalah tiang agama', 'Solat adalah tiang agama Islam. Meninggalkan solat fardu tanpa keuzuran syarak adalah dosa besar. Rasulullah SAW bersabda: "Perkara pertama yang dihisab pada hari kiamat ialah solat." (Hadis riwayat Ahmad dan An-Nasai)', 'standard', array['rukun_islam', 'solat', 'dosa_besar']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 2, 'Rukun Islam & Rukun Iman', 'Beriman kepada kitab-kitab Allah termasuk dalam Rukun Iman yang ke-3. Kitab yang diturunkan kepada Nabi Daud AS ialah kitab Injil.', 'true_false', null, 'Salah', 'Kitab yang diturunkan kepada Nabi Daud AS ialah Kitab Zabur, bukan Injil. Kitab Injil diturunkan kepada Nabi Isa AS. (Rujukan: Surah An-Nisa 4:163)', 'standard', array['rukun_iman', 'kitab_allah', 'zabur']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 2, 'Rukun Islam & Rukun Iman', 'Ahmad tidak menunaikan zakat walaupun sudah cukup haul dan nisab. Pada masa yang sama, dia rajin bersolat dan berpuasa. Berdasarkan Rukun Islam, adakah amalan Ahmad sudah lengkap?', 'mcq', array['Ya, kerana solat dan puasa sudah mencukupi', 'Ya, kerana zakat hanya sunat', 'Tidak, kerana zakat adalah rukun Islam ketiga yang wajib ditunaikan', 'Tidak, kerana dia perlu menunaikan haji dahulu'], 'Tidak, kerana zakat adalah rukun Islam ketiga yang wajib ditunaikan', 'Zakat ialah Rukun Islam yang ketiga dan wajib bagi mereka yang cukup syarat. Meninggalkannya bermakna tidak melengkapkan Rukun Islam. (Rujukan: Surah At-Taubah 9:103)', 'kbat', array['rukun_islam', 'zakat', 'kbat']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 2, 'Rukun Islam & Rukun Iman', 'Rukun Islam yang kelima ialah menunaikan ibadat __________ ke Baitullah bagi mereka yang berkemampuan.', 'fill_blank', null, 'haji', 'Rukun Islam kelima ialah menunaikan haji ke Baitullah (Kaabah) di Makkah bagi mereka yang mampu dari segi kewangan, kesihatan, dan keselamatan perjalanan. (Rujukan: Surah Ali Imran 3:97)', 'easy', array['rukun_islam', 'haji', 'baitullah']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 3, 'Bersuci & Istinjak', 'Najis mughalazah ialah najis yang paling berat. Apakah contoh najis mughalazah?', 'mcq', array['Darah manusia', 'Air kencing bayi lelaki', 'Najis anjing dan babi', 'Air liur kucing'], 'Najis anjing dan babi', 'Najis mughalazah ialah najis yang paling berat iaitu yang berkaitan dengan anjing dan babi. Cara menyucikannya ialah membasuh sebanyak tujuh kali, salah satunya dengan air yang dicampur tanah. (Mazhab Syafie, Hadis riwayat Muslim)', 'standard', array['bersuci', 'najis_mughalazah', 'anjing_babi']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 3, 'Bersuci & Istinjak', 'Apakah cara menyucikan najis mukhafafah (najis ringan) seperti air kencing bayi lelaki yang belum makan selain susu ibu?', 'mcq', array['Dibasuh tujuh kali dengan air', 'Direnjis dengan air yang suci', 'Dijemur di bawah cahaya matahari', 'Disapu dengan kain basah sahaja'], 'Direnjis dengan air yang suci', 'Najis mukhafafah ialah najis ringan seperti air kencing bayi lelaki yang belum makan selain susu ibu. Cara menyucikannya cukup dengan merenjiskan air ke atas tempat yang terkena najis tersebut. (Mazhab Syafie, Hadis riwayat Abu Daud)', 'standard', array['bersuci', 'najis_mukhafafah', 'renjis']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 3, 'Bersuci & Istinjak', 'Najis mutawasitah boleh disucikan dengan cara membasuh hingga hilang warna, bau, dan rasa najis tersebut.', 'true_false', null, 'Benar', 'Najis mutawasitah (najis sederhana) seperti darah, nanah, dan air kencing orang dewasa disucikan dengan membasuh menggunakan air mutlak sehingga hilang sifat-sifat najis iaitu warna, bau, dan rasa. (Mazhab Syafie)', 'easy', array['bersuci', 'najis_mutawasitah', 'cara_bersuci']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 3, 'Bersuci & Istinjak', 'Ali terpijak najis kucing di halaman rumah. Dia mencuci kasutnya dengan air paip sahaja. Adakah kasut Ali sudah suci?', 'mcq', array['Tidak, kerana najis kucing perlu dibasuh tujuh kali', 'Ya, kerana najis kucing adalah najis mutawasitah yang cukup dibasuh hingga hilang sifat najis', 'Tidak, kerana semua najis haiwan perlu disamak', 'Ya, kerana kucing bukan haiwan najis'], 'Ya, kerana najis kucing adalah najis mutawasitah yang cukup dibasuh hingga hilang sifat najis', 'Najis kucing termasuk najis mutawasitah. Cara menyucikannya ialah membasuh dengan air sehingga hilang warna, bau, dan rasa najis. Tidak perlu dibasuh tujuh kali kerana itu hanya untuk najis mughalazah. (Mazhab Syafie)', 'kbat', array['bersuci', 'najis_mutawasitah', 'senario', 'kbat']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 3, 'Bersuci & Istinjak', 'Istinjak ialah amalan membersihkan najis yang keluar dari qubul dan dubur. Alat yang boleh digunakan untuk beristinjak selain air ialah __________.', 'fill_blank', null, 'batu', 'Selain air, istinjak boleh dilakukan menggunakan batu atau benda-benda keras yang suci dan tidak licin (istijirad). Batu mestilah digunakan sekurang-kurangnya tiga kali sapuan. (Mazhab Syafie, Hadis riwayat Al-Bukhari)', 'standard', array['bersuci', 'istinjak', 'alat_istinjak']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 4, 'Wuduk & Tayamum', 'Berapakah jumlah fardu wuduk mengikut Mazhab Syafie?', 'mcq', array['4 fardu', '5 fardu', '6 fardu', '7 fardu'], '6 fardu', 'Fardu wuduk mengikut Mazhab Syafie ada 6 iaitu: (1) niat, (2) membasuh muka, (3) membasuh kedua-dua tangan hingga siku, (4) menyapu sebahagian kepala, (5) membasuh kedua-dua kaki hingga buku lali, dan (6) tertib. (Rujukan: Surah Al-Maidah 5:6, Mazhab Syafie)', 'easy', array['wuduk', 'fardu_wuduk', 'mazhab_syafie']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 4, 'Wuduk & Tayamum', 'Antara berikut, yang manakah BUKAN termasuk perkara sunat wuduk?', 'mcq', array['Membaca Bismillah', 'Membasuh muka', 'Berkumur-kumur', 'Menyelitkan air di celah-celah jari'], 'Membasuh muka', 'Membasuh muka adalah FARDU wuduk, bukan sunat. Membaca Bismillah, berkumur-kumur, dan menyelitkan air di celah-celah jari adalah antara perkara sunat wuduk. (Mazhab Syafie)', 'standard', array['wuduk', 'sunat_wuduk', 'fardu_wuduk']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 4, 'Wuduk & Tayamum', 'Tayamum diharuskan apabila seseorang tidak menemui air atau tidak mampu menggunakan air kerana sakit. Bahan yang digunakan untuk bertayamum ialah __________.', 'fill_blank', null, 'debu tanah', 'Tayamum dilakukan menggunakan debu tanah yang suci. Ia diharuskan apabila tiada air, air tidak mencukupi, atau seseorang tidak mampu menggunakan air kerana sakit. (Rujukan: Surah An-Nisa 4:43, Mazhab Syafie)', 'easy', array['tayamum', 'debu_tanah', 'syarat_tayamum']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 4, 'Wuduk & Tayamum', 'Siti sedang berwuduk tetapi dia membasuh tangan terlebih dahulu sebelum membasuh muka. Adakah wuduk Siti sah mengikut Mazhab Syafie?', 'mcq', array['Sah, kerana semua anggota sudah dibasuh', 'Tidak sah, kerana tertib adalah fardu wuduk dalam Mazhab Syafie', 'Sah, kerana tertib hanya sunat', 'Tidak sah, kerana dia tidak membaca doa'], 'Tidak sah, kerana tertib adalah fardu wuduk dalam Mazhab Syafie', 'Dalam Mazhab Syafie, tertib (mengikut urutan) adalah fardu wuduk yang keenam. Jika anggota wuduk tidak dibasuh mengikut urutan yang betul, wuduk tidak sah. (Mazhab Syafie)', 'kbat', array['wuduk', 'tertib', 'fardu_wuduk', 'senario', 'kbat']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 4, 'Wuduk & Tayamum', 'Menyapu seluruh kepala semasa berwuduk adalah fardu wuduk mengikut Mazhab Syafie.', 'true_false', null, 'Salah', 'Dalam Mazhab Syafie, yang fardu hanyalah menyapu SEBAHAGIAN kepala, bukan seluruh kepala. Menyapu seluruh kepala adalah sunat. Ini berbeza dengan Mazhab Hanbali yang mewajibkan menyapu seluruh kepala. (Mazhab Syafie)', 'standard', array['wuduk', 'fardu_wuduk', 'sapu_kepala']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 5, 'Mandi Wajib', 'Berapakah jumlah fardu mandi wajib mengikut Mazhab Syafie?', 'mcq', array['1 fardu', '2 fardu', '3 fardu', '4 fardu'], '2 fardu', 'Fardu mandi wajib mengikut Mazhab Syafie ada 2 sahaja iaitu: (1) niat, dan (2) meratakan air ke seluruh badan termasuk rambut. (Mazhab Syafie)', 'easy', array['mandi_wajib', 'fardu_mandi', 'mazhab_syafie']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 5, 'Mandi Wajib', 'Antara berikut, yang manakah BUKAN perkara sunat mandi wajib?', 'mcq', array['Membaca Bismillah', 'Berwuduk sebelum mandi', 'Meratakan air ke seluruh badan', 'Menggosok seluruh badan dengan tangan'], 'Meratakan air ke seluruh badan', 'Meratakan air ke seluruh badan adalah FARDU mandi wajib, bukan sunat. Membaca Bismillah, berwuduk sebelum mandi, dan menggosok badan adalah antara perkara sunat mandi wajib. (Mazhab Syafie)', 'standard', array['mandi_wajib', 'sunat_mandi', 'fardu_mandi']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 5, 'Mandi Wajib', 'Apakah sebab utama seseorang Muslim diwajibkan mandi wajib selepas haid?', 'mcq', array['Untuk membersihkan badan dari kuman', 'Untuk mengangkat hadas besar supaya sah menunaikan ibadat', 'Untuk menyegarkan badan selepas berasa penat', 'Untuk memenuhi amalan sunat harian'], 'Untuk mengangkat hadas besar supaya sah menunaikan ibadat', 'Mandi wajib bertujuan mengangkat hadas besar. Seseorang yang berhadas besar tidak sah menunaikan solat, memegang Al-Quran, dan ibadat-ibadat tertentu sehingga dia mandi wajib. (Rujukan: Surah Al-Maidah 5:6)', 'standard', array['mandi_wajib', 'hadas_besar', 'haid']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 5, 'Mandi Wajib', 'Mandi wajib juga dikenali sebagai mandi junub dan ia diwajibkan dalam beberapa keadaan tertentu sahaja, bukan setiap hari.', 'true_false', null, 'Benar', 'Mandi wajib (mandi junub) hanya diwajibkan apabila berlaku perkara-perkara tertentu seperti keluar mani, haid, nifas, bersalin, dan meninggal dunia (dimandikan). Ia bukan amalan harian tetapi mengikut keadaan. (Mazhab Syafie)', 'easy', array['mandi_wajib', 'mandi_junub', 'sebab_wajib']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 5, 'Mandi Wajib', 'Kamal mandi selepas bermain bola tetapi tidak berniat mandi wajib. Kemudian dia terus menunaikan solat. Jika Kamal berhadas besar, adakah solatnya sah?', 'mcq', array['Sah, kerana dia sudah bersih', 'Sah, kerana niat tidak penting dalam mandi', 'Tidak sah, kerana niat adalah fardu mandi wajib', 'Tidak sah, kerana dia tidak berwuduk'], 'Tidak sah, kerana niat adalah fardu mandi wajib', 'Niat adalah fardu pertama mandi wajib dalam Mazhab Syafie. Mandi biasa tanpa niat mengangkat hadas besar tidak mengangkat hadas, maka solat tidak sah. Kamal perlu mengulang mandi dengan niat mandi wajib. (Mazhab Syafie)', 'kbat', array['mandi_wajib', 'niat', 'fardu_mandi', 'senario', 'kbat']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 6, 'Solat Fardu & Toma''ninah', 'Berapakah jumlah rukun solat mengikut Mazhab Syafie?', 'mcq', array['10 rukun', '13 rukun', '15 rukun', '17 rukun'], '13 rukun', 'Rukun solat mengikut Mazhab Syafie ada 13 iaitu: niat, takbiratul ihram, berdiri bagi yang mampu, membaca Al-Fatihah, rukuk, toma''ninah dalam rukuk, i''tidal, toma''ninah dalam i''tidal, sujud dua kali, toma''ninah dalam sujud, duduk antara dua sujud, tasyahud akhir dan duduknya, dan salam. (Mazhab Syafie)', 'standard', array['solat_fardu', 'rukun_solat', 'mazhab_syafie']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 6, 'Solat Fardu & Toma''ninah', 'Apakah maksud toma''ninah dalam solat?', 'mcq', array['Membaca doa dengan suara yang kuat', 'Berdiam seketika sehingga tenang pada setiap rukun fi', 'li', 'Mengangkat tangan ketika takbiratul ihram', 'Membaca selawat ke atas Nabi SAW'], 'Berdiam seketika sehingga tenang pada setiap rukun fi', 'Toma''ninah bermaksud berdiam diri seketika (sekurang-kurangnya kadar masa membaca "Subhanallah") sehingga anggota badan tenang pada setiap rukun fi''li seperti rukuk, i''tidal, sujud, dan duduk antara dua sujud. (Mazhab Syafie, Hadis riwayat Al-Bukhari dan Muslim)', 'standard', array['solat_fardu', 'tomaninah', 'rukun_solat']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 6, 'Solat Fardu & Toma''ninah', 'Antara berikut, yang manakah merupakan syarat sah solat?', 'mcq', array['Membaca surah selepas Al-Fatihah', 'Mengadap kiblat', 'Membaca qunut dalam solat Subuh', 'Duduk tahiyat awal'], 'Mengadap kiblat', 'Mengadap kiblat (Kaabah di Makkah) adalah syarat sah solat. Membaca surah selepas Al-Fatihah dan qunut adalah sunat, manakala tahiyat awal juga sunat (bukan fardu). (Rujukan: Surah Al-Baqarah 2:144, Mazhab Syafie)', 'easy', array['solat_fardu', 'syarat_sah_solat', 'kiblat']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 6, 'Solat Fardu & Toma''ninah', 'Membaca surah Al-Fatihah dalam setiap rakaat solat adalah sunat muakkad, bukan fardu.', 'true_false', null, 'Salah', 'Membaca surah Al-Fatihah adalah RUKUN solat (fardu), bukan sunat. Rasulullah SAW bersabda: "Tidak sah solat seseorang yang tidak membaca Al-Fatihah." (Hadis riwayat Al-Bukhari dan Muslim)', 'standard', array['solat_fardu', 'rukun_solat', 'al_fatihah']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 6, 'Solat Fardu & Toma''ninah', 'Zaid menunaikan solat Zohor tetapi dia tidak berdiam seketika semasa rukuk dan terus bangun ke i''tidal. Adakah solat Zaid sah?', 'mcq', array['Sah, kerana dia sudah melakukan rukuk', 'Sah, kerana toma', 'ninah hanya sunat', 'Tidak sah, kerana toma', 'ninah semasa rukuk adalah rukun solat', 'Tidak sah, kerana dia tidak membaca doa rukuk'], 'Tidak sah, kerana toma', 'Toma''ninah semasa rukuk adalah rukun solat yang wajib dilakukan. Solat seseorang yang tidak toma''ninah semasa rukuk tidak sah dan perlu diulangi. Rasulullah SAW pernah menyuruh seorang lelaki mengulangi solatnya kerana tidak toma''ninah. (Hadis riwayat Al-Bukhari dan Muslim)', 'kbat', array['solat_fardu', 'tomaninah', 'rukun_solat', 'senario', 'kbat']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 7, 'Solat Berjemaah & Masbuk/Muafik', 'Apakah hukum solat berjemaah bagi lelaki yang tidak mempunyai keuzuran?', 'mcq', array['Wajib ain', 'Wajib kifayah', 'Sunat muakkad', 'Harus'], 'Sunat muakkad', 'Hukum solat berjemaah bagi lelaki mengikut Mazhab Syafie ialah sunat muakkad (sunat yang sangat dituntut). Pahala solat berjemaah 27 kali ganda berbanding solat bersendirian. (Hadis riwayat Al-Bukhari dan Muslim)', 'easy', array['solat_berjemaah', 'hukum', 'sunat_muakkad']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 7, 'Solat Berjemaah & Masbuk/Muafik', 'Apakah yang dimaksudkan dengan makmum masbuk?', 'mcq', array['Makmum yang mendapat semua rakaat bersama imam', 'Makmum yang sampai lewat dan tidak sempat mendapat rakaat pertama bersama imam', 'Makmum yang menjadi imam ganti', 'Makmum yang bersolat di saf paling belakang'], 'Makmum yang sampai lewat dan tidak sempat mendapat rakaat pertama bersama imam', 'Makmum masbuk ialah makmum yang tidak sempat mengikuti imam dari awal solat dan ketinggalan satu rakaat atau lebih. Dia perlu menambah rakaat yang tertinggal selepas imam memberi salam. (Mazhab Syafie)', 'standard', array['solat_berjemaah', 'masbuk', 'makmum']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 7, 'Solat Berjemaah & Masbuk/Muafik', 'Makmum muafik ialah makmum yang sempat mendapat sekurang-kurangnya satu rakaat penuh bersama imam dari awal solat.', 'true_false', null, 'Salah', 'Makmum muafik ialah makmum yang sempat mengikuti imam dari awal solat (takbiratul ihram bersama imam) dan mendapat SEMUA rakaat bersama imam. Makmum yang hanya sempat mendapat sebahagian rakaat dipanggil makmum masbuk. (Mazhab Syafie)', 'standard', array['solat_berjemaah', 'muafik', 'makmum']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 7, 'Solat Berjemaah & Masbuk/Muafik', 'Antara berikut, yang manakah merupakan adab solat berjemaah?', 'mcq', array['Makmum berdiri di hadapan imam', 'Makmum hendaklah meluruskan dan merapatkan saf', 'Makmum boleh mendahului pergerakan imam', 'Makmum tidak perlu mengikut bacaan imam'], 'Makmum hendaklah meluruskan dan merapatkan saf', 'Antara adab solat berjemaah ialah meluruskan dan merapatkan saf. Rasulullah SAW bersabda: "Luruskan saf-saf kamu kerana meluruskan saf itu termasuk kesempurnaan solat." (Hadis riwayat Al-Bukhari dan Muslim)', 'easy', array['solat_berjemaah', 'adab', 'saf']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 7, 'Solat Berjemaah & Masbuk/Muafik', 'Hassan sampai di masjid ketika imam sedang rukuk pada rakaat ketiga solat Isyak. Hassan terus bertakbiratul ihram dan mengikuti imam rukuk. Berapakah rakaat yang perlu Hassan tambah selepas imam salam?', 'mcq', array['1 rakaat', '2 rakaat', '3 rakaat', '4 rakaat'], '2 rakaat', 'Solat Isyak ada 4 rakaat. Hassan sempat mendapat rakaat ketiga dan keempat bersama imam (2 rakaat). Selepas imam salam, Hassan perlu bangun dan menambah 2 rakaat lagi untuk melengkapkan 4 rakaat. Ini kerana dia dikira makmum masbuk. (Mazhab Syafie)', 'kbat', array['solat_berjemaah', 'masbuk', 'senario', 'kbat']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 8, 'Puasa Ramadan', 'Antara berikut, yang manakah merupakan syarat wajib berpuasa Ramadan?', 'mcq', array['Tinggal di negara Islam', 'Berakal, baligh, dan mampu berpuasa', 'Berumur lebih dari 15 tahun sahaja', 'Bersekolah di sekolah agama'], 'Berakal, baligh, dan mampu berpuasa', 'Syarat wajib puasa Ramadan ialah Islam, berakal, baligh, dan mampu berpuasa. Orang yang tidak memenuhi syarat ini tidak diwajibkan berpuasa. (Rujukan: Surah Al-Baqarah 2:183-185)', 'easy', array['puasa', 'syarat_wajib', 'ramadan']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 8, 'Puasa Ramadan', 'Apakah perkara yang disunatkan semasa berpuasa?', 'mcq', array['Tidur sepanjang hari', 'Menyegerakan berbuka puasa apabila masuk waktu Maghrib', 'Melambat-lambatkan waktu sahur', 'Banyak berbelanja di bazar Ramadan'], 'Menyegerakan berbuka puasa apabila masuk waktu Maghrib', 'Antara sunat puasa ialah menyegerakan berbuka apabila masuk waktu Maghrib. Rasulullah SAW bersabda: "Manusia akan sentiasa berada dalam kebaikan selagi mereka menyegerakan berbuka puasa." (Hadis riwayat Al-Bukhari dan Muslim)', 'standard', array['puasa', 'sunat_puasa', 'berbuka']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 8, 'Puasa Ramadan', 'Apakah perkara yang makruh dilakukan semasa berpuasa?', 'mcq', array['Membaca Al-Quran', 'Bersikat gigi menggunakan ubat gigi', 'Berkumur-kumur secara berlebih-lebihan sehingga hampir termasuk air ke kerongkong', 'Minum air ketika sahur'], 'Berkumur-kumur secara berlebih-lebihan sehingga hampir termasuk air ke kerongkong', 'Berkumur-kumur secara berlebihan (mubalghah) semasa berpuasa adalah makruh kerana dikhuatiri air akan termasuk ke dalam kerongkong dan membatalkan puasa. (Mazhab Syafie, Hadis riwayat Abu Daud)', 'standard', array['puasa', 'makruh_puasa', 'berkumur']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 8, 'Puasa Ramadan', 'Makan sahur sebelum waktu Subuh adalah rukun puasa yang wajib dilakukan.', 'true_false', null, 'Salah', 'Makan sahur adalah SUNAT, bukan rukun atau wajib. Puasa tetap sah walaupun seseorang tidak bersahur. Namun, sahur sangat digalakkan kerana Rasulullah SAW bersabda: "Bersahurlah kamu, sesungguhnya pada sahur itu ada berkat." (Hadis riwayat Al-Bukhari dan Muslim)', 'standard', array['puasa', 'sahur', 'sunat_puasa']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 8, 'Puasa Ramadan', 'Fatimah berpuasa pada bulan Ramadan. Pada waktu tengah hari, dia terlupa dan terminum air. Selepas teringat, dia terus berhenti minum. Adakah puasa Fatimah batal?', 'mcq', array['Ya, kerana dia sudah minum air', 'Ya, kerana dia tidak menjaga puasanya', 'Tidak, kerana makan atau minum kerana lupa tidak membatalkan puasa', 'Tidak, kerana air tidak membatalkan puasa'], 'Tidak, kerana makan atau minum kerana lupa tidak membatalkan puasa', 'Makan atau minum kerana lupa tidak membatalkan puasa. Rasulullah SAW bersabda: "Sesiapa yang terlupa sedang dia berpuasa, lalu dia makan atau minum, maka hendaklah dia menyempurnakan puasanya kerana sesungguhnya Allah yang memberinya makan dan minum." (Hadis riwayat Al-Bukhari dan Muslim)', 'kbat', array['puasa', 'terlupa', 'senario', 'kbat']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 9, 'Adab & Akhlak Islamiah', 'Apakah adab yang betul semasa makan mengikut sunnah Rasulullah SAW?', 'mcq', array['Makan sambil berdiri', 'Makan dengan tangan kanan dan membaca Bismillah', 'Makan dengan cepat supaya tidak membazir masa', 'Makan sehingga terlalu kenyang'], 'Makan dengan tangan kanan dan membaca Bismillah', 'Adab makan mengikut sunnah Rasulullah SAW ialah makan dengan tangan kanan, membaca Bismillah sebelum makan, dan makan yang terdekat. Rasulullah SAW bersabda: "Wahai anak muda, sebutlah nama Allah, makan dengan tangan kananmu, dan makan dari yang terdekat denganmu." (Hadis riwayat Al-Bukhari dan Muslim)', 'easy', array['adab', 'adab_makan', 'sunnah']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 9, 'Adab & Akhlak Islamiah', 'Antara berikut, yang manakah merupakan adab terhadap ibu bapa yang dituntut dalam Islam?', 'mcq', array['Mematuhi arahan ibu bapa dalam semua perkara termasuk yang haram', 'Berkata-kata dengan lemah lembut dan tidak membentak mereka', 'Memberi wang sahaja tanpa perlu meluangkan masa bersama mereka', 'Menuruti semua kehendak ibu bapa walaupun bertentangan dengan ajaran Islam'], 'Berkata-kata dengan lemah lembut dan tidak membentak mereka', 'Islam menyuruh kita berkata-kata dengan lemah lembut kepada ibu bapa dan tidak membentak mereka. Allah SWT berfirman: "Janganlah kamu berkata ''ah'' kepada mereka berdua dan janganlah kamu membentak mereka." (Rujukan: Surah Al-Isra'' 17:23)', 'standard', array['adab', 'adab_ibu_bapa', 'birrul_walidain']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 9, 'Adab & Akhlak Islamiah', 'Apakah adab yang betul semasa hendak tidur mengikut sunnah Rasulullah SAW?', 'mcq', array['Tidur meniarap', 'Tidur mengiring ke kiri', 'Membaca doa tidur dan tidur mengiring ke kanan', 'Tidur dalam keadaan lampu terbuka terang'], 'Membaca doa tidur dan tidur mengiring ke kanan', 'Adab tidur mengikut sunnah ialah membaca doa tidur, tidur mengiring ke kanan (bertumpu pada rusuk kanan), membaca ayat Al-Kursi, dan tiga Qul (Al-Ikhlas, Al-Falaq, An-Nas). Rasulullah SAW bersabda: "Apabila kamu hendak tidur, berwuduklah, kemudian berbaringlah di atas rusuk kananmu." (Hadis riwayat Al-Bukhari dan Muslim)', 'easy', array['adab', 'adab_tidur', 'sunnah']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 9, 'Adab & Akhlak Islamiah', 'Islam mengajar kita supaya menghormati guru sebagaimana kita menghormati ibu bapa kerana guru mendidik kita dengan ilmu pengetahuan.', 'true_false', null, 'Benar', 'Islam sangat memuliakan guru kerana mereka menyampaikan ilmu. Rasulullah SAW sendiri mengajar umat tentang kepentingan menghormati guru dan penuntut ilmu. Saidina Ali RA berkata: "Sesiapa yang mengajarku satu huruf, maka dia adalah tuanku." (Athar Saidina Ali RA)', 'standard', array['adab', 'adab_guru', 'ilmu']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 9, 'Adab & Akhlak Islamiah', 'Aisyah nampak rakannya, Huda, sedang menangis kerana diejek oleh kawan-kawan lain. Apakah tindakan yang paling sesuai mengikut adab Islam?', 'mcq', array['Mengabaikan Huda kerana bukan urusannya', 'Turut mengejek Huda supaya dia belajar menjadi kuat', 'Memujuk Huda, menegur kawan-kawan yang mengejek, dan melaporkan kepada guru', 'Menyuruh Huda membalas ejek mereka'], 'Memujuk Huda, menegur kawan-kawan yang mengejek, dan melaporkan kepada guru', 'Islam mengajar kita supaya menyantuni rakan yang dizalimi dan mencegah kemungkaran. Rasulullah SAW bersabda: "Tolonglah saudaramu sama ada dia yang menzalimi atau dia yang dizalimi." (Hadis riwayat Al-Bukhari). Menegur yang berbuat salah dan membantu yang ditindas adalah akhlak mulia.', 'kbat', array['adab', 'adab_rakan', 'amar_makruf', 'senario', 'kbat']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 10, 'Sirah Nabawiyah', 'Apakah peristiwa Hijrah dalam sejarah Islam?', 'mcq', array['Nabi Muhammad SAW berpindah dari Makkah ke Madinah', 'Nabi Muhammad SAW menakluki kota Makkah', 'Nabi Muhammad SAW pergi berperang ke Badar', 'Nabi Muhammad SAW menerima wahyu pertama'], 'Nabi Muhammad SAW berpindah dari Makkah ke Madinah', 'Hijrah ialah peristiwa perpindahan Nabi Muhammad SAW dan para sahabat dari Makkah ke Madinah (dahulunya Yathrib) pada tahun 622 Masihi. Peristiwa ini menjadi titik permulaan kalendar Islam (Hijriah). (Rujukan: Sirah Ibnu Hisyam)', 'easy', array['sirah', 'hijrah', 'makkah_madinah']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 10, 'Sirah Nabawiyah', 'Perang Badar berlaku pada tahun kedua Hijrah. Berapakah anggaran jumlah tentera Muslim dalam peperangan tersebut?', 'mcq', array['Kira-kira 100 orang', 'Kira-kira 313 orang', 'Kira-kira 1000 orang', 'Kira-kira 3000 orang'], 'Kira-kira 313 orang', 'Perang Badar berlaku pada 17 Ramadan tahun ke-2 Hijrah. Tentera Muslim berjumlah kira-kira 313 orang menghadapi tentera Quraisy yang berjumlah kira-kira 1000 orang. Allah SWT memberikan kemenangan kepada umat Islam. (Rujukan: Surah Al-Anfal 8:9, Sirah Ibnu Hisyam)', 'standard', array['sirah', 'perang_badar', 'tentera_muslim']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 10, 'Sirah Nabawiyah', 'Perjanjian Hudaibiyah ialah perjanjian damai antara umat Islam dengan kaum Quraisy Makkah. Pada tahun berapakah perjanjian ini berlaku?', 'mcq', array['Tahun ke-4 Hijrah', 'Tahun ke-6 Hijrah', 'Tahun ke-8 Hijrah', 'Tahun ke-10 Hijrah'], 'Tahun ke-6 Hijrah', 'Perjanjian Hudaibiyah berlaku pada tahun ke-6 Hijrah di kawasan Hudaibiyah, berhampiran Makkah. Antara syarat perjanjian ini ialah gencatan senjata selama 10 tahun. Allah SWT menyebut perjanjian ini sebagai "kemenangan yang nyata" (al-fath al-mubin). (Rujukan: Surah Al-Fath 48:1)', 'standard', array['sirah', 'perjanjian_hudaibiyah', 'quraisy']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 10, 'Sirah Nabawiyah', 'Fathu Makkah (Pembukaan Kota Makkah) berlaku secara aman tanpa pertumpahan darah yang besar. Nabi Muhammad SAW mengampunkan penduduk Makkah selepas memasuki kota tersebut.', 'true_false', null, 'Benar', 'Fathu Makkah berlaku pada tahun ke-8 Hijrah. Nabi Muhammad SAW memasuki Makkah secara aman dengan kira-kira 10,000 tentera Muslim. Baginda mengampunkan penduduk Makkah dengan bersabda: "Pergilah kamu, kamu semua bebas." Ini menunjukkan sifat pemaaf dan kasih sayang Rasulullah SAW. (Rujukan: Sirah Ibnu Hisyam, Hadis riwayat Al-Baihaqi)', 'easy', array['sirah', 'fathu_makkah', 'pengampunan']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('t4', 10, 'Sirah Nabawiyah', 'Semasa peristiwa Hijrah, Nabi Muhammad SAW dan Abu Bakar As-Siddiq bersembunyi di dalam sebuah gua. Apakah nama gua tersebut dan apakah pengajaran utama daripada peristiwa ini?', 'mcq', array['Gua Hira', ' - pengajaran tentang kepentingan beribadat', 'Gua Thur - pengajaran tentang tawakkal kepada Allah', 'Gua Uhud - pengajaran tentang ketabahan berperang', 'Gua Khandaq - pengajaran tentang strategi peperangan'], 'Gua Thur - pengajaran tentang tawakkal kepada Allah', 'Nabi SAW dan Abu Bakar bersembunyi di Gua Thur selama tiga hari semasa Hijrah. Ketika kaum Quraisy hampir menemui mereka, Nabi SAW berkata kepada Abu Bakar: "Jangan berdukacita, sesungguhnya Allah bersama kita." Pengajaran utama ialah tawakkal (berserah) kepada Allah setelah berusaha. (Rujukan: Surah At-Taubah 9:40)', 'kbat', array['sirah', 'hijrah', 'gua_thur', 'tawakkal', 'kbat']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 1, 'Dua Kalimah Syahadah', 'Kalimah Syahadah kedua ialah pengakuan bahawa Nabi Muhammad SAW adalah ________ Allah.', 'fill_blank', null, 'Rasul', 'Syahadah kedua berbunyi: "Wa asyhadu anna Muhammadar Rasulullah" yang bermaksud "Dan aku naik saksi bahawa Nabi Muhammad itu Rasul (utusan) Allah." Pengakuan ini merangkumi kewajipan mengikut sunnah Rasulullah SAW dalam setiap aspek kehidupan. (Rujukan: Hadis riwayat Bukhari no. 8 - Hadis Jibril)', 'standard', array['syahadah', 'tauhid', 'nabi_muhammad']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 1, 'Dua Kalimah Syahadah', 'Ahmad mengucap dua kalimah syahadah di hadapan saksi tetapi dalam hatinya tidak meyakini kewujudan Allah. Apakah status keimanannya menurut perspektif akidah Islam?', 'mcq', array['Sah keimanannya kerana telah melafazkan syahadah di hadapan saksi', 'Tidak sah kerana syarat sah syahadah memerlukan keyakinan hati (al-yaqin) selain lafaz lisan', 'Sah kerana niat dalam hati tidak dikira dalam hukum Islam', 'Perlu mengulang syahadah tiga kali untuk menjadi sah'], 'Tidak sah kerana syarat sah syahadah memerlukan keyakinan hati (al-yaqin) selain lafaz lisan', 'Menurut jumhur ulama, syarat sah syahadah merangkumi: (1) al-''ilm (mengetahui makna), (2) al-yaqin (meyakini tanpa keraguan), (3) al-qabul (menerima), (4) al-inqiyad (patuh), (5) al-sidq (benar dari hati), (6) al-ikhlas (ikhlas). Tanpa keyakinan hati, lafaz sahaja tidak mencukupi. (Rujukan: Surah Muhammad 47:19, Kitab al-Tauhid oleh Syaikh Muhammad bin Abdul Wahhab)', 'kbat', array['syahadah', 'tauhid', 'syarat_syahadah']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 2, 'Rukun Islam & Rukun Iman', 'Berapakah bilangan Rukun Iman dalam Islam?', 'mcq', array['5', '6', '7', '4'], '6', 'Rukun Iman ada 6 perkara: (1) Beriman kepada Allah, (2) Beriman kepada Malaikat, (3) Beriman kepada Kitab, (4) Beriman kepada Rasul, (5) Beriman kepada Hari Akhirat, (6) Beriman kepada Qada dan Qadar. (Rujukan: Hadis Jibril, riwayat Muslim no. 8)', 'easy', array['rukun_iman', 'asas_iman']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 2, 'Rukun Islam & Rukun Iman', 'Seorang Muslim menunaikan solat lima waktu dan berpuasa Ramadan tetapi menafikan kewajipan menunaikan zakat. Apakah implikasi tindakannya menurut hukum Islam?', 'mcq', array['Tiada kesan kerana zakat bukan wajib bagi semua orang', 'Dianggap fasiq kerana meninggalkan salah satu Rukun Islam tanpa uzur', 'Boleh dikira kafir kerana mengingkari kewajipan yang telah disepakati (ijmak) sebagai rukun Islam', 'Hanya berdosa ringan kerana telah melaksanakan rukun lain'], 'Boleh dikira kafir kerana mengingkari kewajipan yang telah disepakati (ijmak) sebagai rukun Islam', 'Menurut jumhur ulama, sesiapa yang mengingkari (juhud) kewajipan zakat sedangkan ia mengetahui hukumnya, maka dia boleh terkeluar daripada Islam kerana mengingkari perkara yang telah sabit secara qat''i dalam al-Quran. Berbeza dengan orang yang meninggalkan tanpa mengingkari kewajipannya, maka dia dianggap fasiq. (Rujukan: Surah at-Taubah 9:34-35, Ijmak ulama tentang kewajipan zakat)', 'kbat', array['rukun_islam', 'zakat', 'hukum_ingkar']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 2, 'Rukun Islam & Rukun Iman', 'Beriman kepada kitab-kitab Allah bermaksud kita wajib mengamalkan semua kandungan Taurat, Zabur, dan Injil yang asal.', 'true_false', null, 'Salah', 'Beriman kepada kitab-kitab terdahulu bermaksud mempercayai bahawa kitab-kitab tersebut pernah diturunkan oleh Allah kepada rasul-rasul-Nya. Namun, umat Islam hanya wajib mengamalkan al-Quran kerana ia merupakan kitab terakhir yang memansuhkan (nasakh) hukum-hukum kitab terdahulu. Kitab-kitab sebelumnya juga telah mengalami perubahan (tahrif). (Rujukan: Surah al-Maidah 5:48)', 'standard', array['rukun_iman', 'kitab_allah', 'tahrif']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 2, 'Rukun Islam & Rukun Iman', 'Rukun Islam yang ketiga ialah menunaikan ________ bagi mereka yang cukup syarat.', 'fill_blank', null, 'zakat', 'Rukun Islam yang ketiga ialah menunaikan zakat. Kewajipan zakat disebut seiring dengan solat di banyak tempat dalam al-Quran, menunjukkan betapa pentingnya ibadat ini. (Rujukan: Surah al-Baqarah 2:43 - "Dan dirikanlah solat, tunaikanlah zakat...")', 'standard', array['rukun_islam', 'zakat']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 2, 'Rukun Islam & Rukun Iman', 'Apakah hubungan antara Rukun Iman dan Rukun Islam dari sudut pandang ilmu tauhid?', 'mcq', array['Kedua-duanya tidak berkaitan dan boleh diamalkan secara terpisah', 'Rukun Iman adalah asas keyakinan dalaman manakala Rukun Islam adalah manifestasi amalan zahir daripada keimanan tersebut', 'Rukun Islam lebih penting daripada Rukun Iman kerana melibatkan amalan fizikal', 'Rukun Iman hanya untuk golongan ulama manakala Rukun Islam untuk orang awam'], 'Rukun Iman adalah asas keyakinan dalaman manakala Rukun Islam adalah manifestasi amalan zahir daripada keimanan tersebut', 'Iman (keyakinan hati) dan Islam (amalan zahir) saling melengkapi. Hadis Jibril menerangkan bahawa iman adalah kepercayaan dalaman (batin) manakala Islam adalah pengamalan luaran (zahir). Keduanya tidak boleh dipisahkan - amalan tanpa iman tidak diterima, dan iman tanpa amalan adalah tidak sempurna. (Rujukan: Hadis Jibril, riwayat Muslim no. 8; Surah al-Hujurat 49:14)', 'kbat', array['rukun_iman', 'rukun_islam', 'tauhid', 'hubungan_iman_islam']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 3, 'Bersuci & Istinjak', 'Air hujan yang mengalir melalui longkang dan bercampur dengan najis tetapi warna, bau, dan rasanya tidak berubah. Apakah hukum air tersebut jika jumlahnya melebihi dua kolah?', 'mcq', array['Haram digunakan untuk bersuci kerana telah bercampur najis', 'Suci dan menyucikan (tahur) kerana melebihi dua kolah dan sifatnya tidak berubah', 'Makruh digunakan untuk bersuci', 'Mesti ditapis terlebih dahulu sebelum boleh digunakan'], 'Suci dan menyucikan (tahur) kerana melebihi dua kolah dan sifatnya tidak berubah', 'Menurut Mazhab Syafie, air yang melebihi dua kolah (lebih kurang 270 liter) tidak menjadi najis walaupun bercampur dengan najis, selagi mana tiga sifatnya (warna, bau, rasa) tidak berubah. Ini berdasarkan hadis: "Apabila air mencapai dua kolah, ia tidak menanggung kotoran (najis)." (Rujukan: Hadis riwayat Abu Daud no. 63; Kitab Fiqh Manhaji, Jilid 1)', 'kbat', array['bersuci', 'air_dua_kolah', 'najis', 'fiqh_syafie']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 3, 'Bersuci & Istinjak', 'Manakah antara berikut BUKAN termasuk dalam kategori najis mukhaffafah (najis ringan)?', 'mcq', array['Air kencing bayi lelaki yang belum makan selain susu ibu', 'Air kencing bayi perempuan yang berumur kurang 2 tahun', 'Air kencing budak lelaki yang belum berumur dua tahun dan tidak memakan makanan selain susu', 'Semua pilihan di atas adalah najis mukhaffafah'], 'Air kencing bayi perempuan yang berumur kurang 2 tahun', 'Najis mukhaffafah hanya merujuk kepada air kencing bayi lelaki yang belum makan apa-apa selain susu ibu dan belum berumur dua tahun. Air kencing bayi perempuan termasuk dalam najis mutawassitah (sederhana) dan perlu dibasuh dengan cara biasa. (Rujukan: Hadis riwayat Bukhari no. 222 dan Muslim no. 287; Kitab Fiqh Manhaji)', 'standard', array['bersuci', 'najis_mukhaffafah', 'kategori_najis']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 3, 'Bersuci & Istinjak', 'Arak yang bertukar menjadi cuka secara semula jadi (tanpa campur tangan manusia) dianggap suci melalui proses istihalah menurut Mazhab Syafie.', 'true_false', null, 'Benar', 'Istihalah bermaksud perubahan sesuatu benda najis kepada benda lain yang suci. Menurut Mazhab Syafie, arak yang bertukar menjadi cuka secara tabii (semula jadi) tanpa dicampur dengan bahan lain, maka ia menjadi suci. Namun, jika perubahan itu berlaku dengan campur tangan manusia (seperti menambah garam), maka ia kekal najis. (Rujukan: Kitab al-Majmu'' oleh Imam Nawawi; Hadis riwayat Muslim)', 'kbat', array['bersuci', 'istihalah', 'najis', 'fiqh_syafie']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 3, 'Bersuci & Istinjak', 'Najis yang paling berat dan memerlukan 7 kali basuhan (satu daripadanya bercampur tanah) ialah najis ________.', 'fill_blank', null, 'mughallazah', 'Najis mughallazah (berat) merujuk kepada najis anjing dan babi serta apa yang lahir daripada percampuran kedua-duanya. Cara menyucikannya ialah dengan membasuh tujuh kali, salah satu basuhannya dicampur dengan tanah yang suci. (Rujukan: Hadis riwayat Muslim no. 279; Kitab Fiqh Manhaji, Jilid 1)', 'standard', array['bersuci', 'najis_mughallazah', 'kategori_najis']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 3, 'Bersuci & Istinjak', 'Apakah perbezaan utama antara istinjak menggunakan air dan istijmar (menggunakan batu)?', 'mcq', array['Tiada perbezaan kerana kedua-duanya sama hukumnya', 'Istinjak dengan air menyucikan sepenuhnya manakala istijmar hanya menghilangkan ain najis sahaja', 'Istijmar lebih afdal daripada istinjak dengan air', 'Istijmar hanya boleh digunakan di kawasan padang pasir sahaja'], 'Istinjak dengan air menyucikan sepenuhnya manakala istijmar hanya menghilangkan ain najis sahaja', 'Istinjak dengan air lebih sempurna kerana ia menyucikan tempat yang terkena najis sepenuhnya. Istijmar (menggunakan batu atau tisu) hanya menghilangkan ain (benda) najis sahaja dan dibenarkan dengan syarat sekurang-kurangnya tiga kali sapu sehingga bersih. Yang paling afdal ialah menggabungkan kedua-duanya - istijmar dahulu kemudian istinjak dengan air. (Rujukan: Hadis riwayat Bukhari no. 155; Kitab al-Umm oleh Imam Syafie)', 'standard', array['bersuci', 'istinjak', 'istijmar']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 4, 'Wuduk & Tayamum', 'Manakah antara berikut merupakan perkara yang membatalkan wuduk?', 'mcq', array['Makan dan minum', 'Tidur dengan punggung tidak tetap di tempat duduk', 'Bersentuhan dengan orang bukan mahram melalui pakaian', 'Bercakap semasa berwuduk'], 'Tidur dengan punggung tidak tetap di tempat duduk', 'Menurut Mazhab Syafie, tidur yang membatalkan wuduk ialah tidur yang punggungnya tidak tetap pada tempat duduknya (tidak mantap). Jika seseorang tidur dalam keadaan duduk dan punggungnya tetap mantap, wuduknya tidak batal. Makan, minum, dan bercakap semasa wuduk tidak membatalkan wuduk. (Rujukan: Hadis riwayat Ahmad dan Tirmizi; Kitab Fiqh Manhaji, Jilid 1)', 'standard', array['wuduk', 'batal_wuduk', 'fiqh_syafie']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 4, 'Wuduk & Tayamum', 'Seorang pesakit yang mempunyai luka balut (pembalut perubatan) pada tangannya ingin berwuduk. Apakah hukum menyapu atas balutan tersebut menurut Mazhab Syafie?', 'mcq', array['Wajib menanggalkan balutan dan membasuh luka tersebut', 'Harus menyapu atas balutan (masah al-jabirah) sebagai ganti membasuh anggota yang dibalut', 'Tidak perlu membasuh atau menyapu anggota yang dibalut sama sekali', 'Wajib bertayamum dan tidak boleh berwuduk'], 'Harus menyapu atas balutan (masah al-jabirah) sebagai ganti membasuh anggota yang dibalut', 'Menurut Mazhab Syafie, apabila seseorang mempunyai luka yang dibalut dan akan mendatangkan mudarat jika dibuka, maka diharuskan menyapu (masah) atas permukaan balutan tersebut sebagai ganti membasuh. Ini dikenali sebagai masah al-jabirah. Syaratnya ialah balutan itu diletakkan dalam keadaan suci dan tidak melampaui kawasan luka. (Rujukan: Hadis riwayat Abu Daud; Kitab al-Majmu'' oleh Imam Nawawi)', 'kbat', array['wuduk', 'masah_jabirah', 'uzur', 'fiqh_syafie']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 4, 'Wuduk & Tayamum', 'Tertib (melakukan rukun wuduk mengikut susunan yang betul) merupakan sunat wuduk dan bukan rukun.', 'true_false', null, 'Salah', 'Tertib merupakan salah satu rukun wuduk menurut Mazhab Syafie, bukan sunat. Rukun wuduk ada 6 perkara: (1) niat, (2) membasuh muka, (3) membasuh kedua-dua tangan hingga siku, (4) menyapu sebahagian kepala, (5) membasuh kedua-dua kaki hingga buku lali, (6) tertib. Tanpa tertib, wuduk tidak sah. (Rujukan: Surah al-Maidah 5:6; Kitab Fiqh Manhaji, Jilid 1)', 'standard', array['wuduk', 'rukun_wuduk', 'tertib']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 4, 'Wuduk & Tayamum', 'Syarat sah tayamum yang pertama ialah masuknya ________ solat fardu.', 'fill_blank', null, 'waktu', 'Menurut Mazhab Syafie, tayamum hanya sah dilakukan setelah masuk waktu solat fardu. Ini kerana tayamum bersifat rukhsah (keringanan) dan terikat dengan waktu. Setiap kali masuk waktu solat baru, tayamum perlu dilakukan semula. (Rujukan: Kitab Fiqh Manhaji, Jilid 1; Kitab al-Umm oleh Imam Syafie)', 'standard', array['tayamum', 'syarat_tayamum', 'fiqh_syafie']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 4, 'Wuduk & Tayamum', 'Ali berada dalam perjalanan jauh dan kehabisan air. Dia menjumpai sedikit air yang hanya cukup untuk membasuh muka dan tangan sahaja. Apakah yang perlu dilakukan Ali?', 'mcq', array['Berwuduk dengan air yang ada dan mengabaikan anggota yang tidak cukup air', 'Menggunakan air tersebut untuk membasuh anggota wuduk yang mampu dan bertayamum untuk bahagian yang tidak cukup air', 'Meninggalkan wuduk sepenuhnya dan bertayamum sahaja', 'Menggunakan air tersebut untuk minum dan bertayamum sahaja'], 'Menggunakan air tersebut untuk membasuh anggota wuduk yang mampu dan bertayamum untuk bahagian yang tidak cukup air', 'Menurut pandangan muktamad Mazhab Syafie, jika air tidak mencukupi untuk semua anggota wuduk, wajib menggunakan air yang ada untuk membasuh anggota wuduk yang mampu mengikut tertib, kemudian bertayamum bagi anggota selebihnya. Ini kerana air wajib digunakan selagi ada sebelum beralih kepada tayamum. (Rujukan: Kitab al-Majmu'' oleh Imam Nawawi; Kitab Fiqh Manhaji)', 'kbat', array['wuduk', 'tayamum', 'rukhsah', 'fiqh_syafie']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 5, 'Mandi Wajib', 'Manakah antara berikut merupakan sebab-sebab yang mewajibkan mandi wajib?', 'mcq', array['Berpeluh banyak selepas bersenam', 'Keluar air mani dengan syarat-syaratnya', 'Terkena air hujan', 'Bermimpi tanpa keluar apa-apa'], 'Keluar air mani dengan syarat-syaratnya', 'Sebab-sebab mandi wajib termasuk: (1) keluar air mani, (2) persetubuhan (walaupun tanpa keluar mani), (3) haid, (4) nifas, (5) wiladah (melahirkan anak), (6) mati (dimandikan). Berpeluh, terkena hujan, atau bermimpi tanpa keluar mani tidak mewajibkan mandi. (Rujukan: Hadis riwayat Muslim no. 343; Kitab Fiqh Manhaji, Jilid 1)', 'standard', array['mandi_wajib', 'sebab_mandi', 'fiqh_syafie']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 5, 'Mandi Wajib', 'Apakah perbezaan antara rukun mandi wajib dan sunat mandi wajib dari segi kesannya terhadap kesahan mandi?', 'mcq', array['Tiada perbezaan kerana kedua-duanya wajib dilakukan', 'Meninggalkan rukun membatalkan mandi manakala meninggalkan sunat mengurangkan pahala tetapi mandi tetap sah', 'Sunat mandi lebih penting daripada rukun mandi', 'Rukun hanya perlu dilakukan sekali seumur hidup manakala sunat setiap kali mandi'], 'Meninggalkan rukun membatalkan mandi manakala meninggalkan sunat mengurangkan pahala tetapi mandi tetap sah', 'Rukun mandi wajib ada dua: (1) niat, dan (2) meratakan air ke seluruh badan. Tanpa mana-mana rukun, mandi tidak sah. Sunat mandi pula termasuk membaca bismillah, berwuduk sebelum mandi, menggosok badan, dan berdoa. Meninggalkan sunat tidak membatalkan mandi tetapi mengurangkan keafdalan. (Rujukan: Kitab Fiqh Manhaji, Jilid 1; Kitab al-Umm oleh Imam Syafie)', 'kbat', array['mandi_wajib', 'rukun_mandi', 'sunat_mandi', 'fiqh_syafie']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 5, 'Mandi Wajib', 'Seseorang yang telah melakukan mandi wajib dengan sempurna tidak perlu lagi berwuduk untuk menunaikan solat.', 'true_false', null, 'Salah', 'Menurut Mazhab Syafie, mandi wajib tidak menggantikan wuduk secara automatik. Seseorang tetap perlu berwuduk untuk solat walaupun telah mandi wajib, KECUALI jika dia berniat wuduk bersama niat mandi wajib (menggabungkan niat). Jika hanya berniat mandi wajib sahaja tanpa niat wuduk, maka dia perlu berwuduk secara berasingan. (Rujukan: Kitab al-Majmu'' oleh Imam Nawawi; Kitab Fiqh Manhaji)', 'standard', array['mandi_wajib', 'wuduk', 'niat', 'fiqh_syafie']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 5, 'Mandi Wajib', 'Rukun mandi wajib yang pertama ialah ________ untuk mengangkat hadas besar.', 'fill_blank', null, 'niat', 'Niat merupakan rukun pertama mandi wajib. Niat dilakukan dalam hati serentak dengan permulaan membasuh anggota badan. Contoh niat mandi junub: "Sahaja aku mandi mengangkat hadas besar kerana Allah Taala." (Rujukan: Hadis "Innamal a''malu binniyat" - riwayat Bukhari no. 1 dan Muslim no. 1907)', 'easy', array['mandi_wajib', 'rukun_mandi', 'niat']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 5, 'Mandi Wajib', 'Fatimah mendapati rambutnya yang diikat sangat tebal dan sukar untuk air menembusi ke kulit kepalanya semasa mandi wajib. Apakah hukumnya jika air tidak sampai ke kulit kepala?', 'mcq', array['Mandi tetap sah kerana rambut sudah basah', 'Mandi tidak sah kerana rukun meratakan air ke seluruh badan termasuk kulit kepala tidak sempurna', 'Sah jika dia berniat dengan ikhlas', 'Hanya perlu mengulangi basuhan kepala sahaja tanpa perlu mengulang keseluruhan mandi'], 'Mandi tidak sah kerana rukun meratakan air ke seluruh badan termasuk kulit kepala tidak sempurna', 'Rukun kedua mandi wajib ialah meratakan air ke seluruh badan termasuk kulit kepala, bawah lipatan kulit, dan celah-celah rambut. Jika terdapat bahagian badan yang tidak dibasahi air walaupun sedikit, mandi tidak sah. Wanita wajib menguraikan rambut jika ikatan rambut menghalang air daripada sampai ke kulit kepala. (Rujukan: Hadis riwayat Muslim no. 330; Kitab Fiqh Manhaji, Jilid 1)', 'kbat', array['mandi_wajib', 'rukun_mandi', 'rambut', 'fiqh_syafie']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 6, 'Solat Fardu & Toma''ninah', 'Berapakah bilangan rukun solat menurut Mazhab Syafie?', 'mcq', array['10', '13', '17', '14'], '13', 'Menurut Mazhab Syafie, rukun solat ada 13 perkara: (1) niat, (2) takbiratul ihram, (3) berdiri bagi yang mampu, (4) membaca al-Fatihah, (5) rukuk, (6) toma''ninah dalam rukuk, (7) iktidal, (8) toma''ninah dalam iktidal, (9) sujud dua kali, (10) toma''ninah dalam sujud, (11) duduk antara dua sujud, (12) tahiyyat akhir bersama duduk, (13) salam. (Rujukan: Kitab Fiqh Manhaji, Jilid 1)', 'standard', array['solat', 'rukun_solat', 'fiqh_syafie']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 6, 'Solat Fardu & Toma''ninah', 'Hassan solat Zohor tetapi terlupa membaca surah al-Fatihah pada rakaat kedua. Dia hanya menyedarinya ketika sudah berada pada rakaat ketiga. Apakah yang perlu dilakukan?', 'mcq', array['Meneruskan solat kerana al-Fatihah boleh ditinggalkan pada satu rakaat', 'Membatalkan solat dan memulakan semula dari awal', 'Rakaat yang tertinggal al-Fatihah tidak dikira dan perlu diganti - dia menambah satu rakaat di akhir dan melakukan sujud sahwi', 'Membaca al-Fatihah dua kali pada rakaat ketiga sebagai ganti'], 'Rakaat yang tertinggal al-Fatihah tidak dikira dan perlu diganti - dia menambah satu rakaat di akhir dan melakukan sujud sahwi', 'Membaca al-Fatihah adalah rukun pada setiap rakaat. Jika seseorang meninggalkan al-Fatihah pada satu rakaat, rakaat tersebut tidak dikira sah. Dia perlu menambah satu rakaat sebagai ganti dan melakukan sujud sahwi sebelum salam kerana telah meninggalkan rukun secara tidak sengaja. (Rujukan: Hadis "La solata liman lam yaqra'' bi fatihati al-kitab" - riwayat Bukhari no. 756; Kitab Fiqh Manhaji)', 'kbat', array['solat', 'rukun_solat', 'al_fatihah', 'sujud_sahwi']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 6, 'Solat Fardu & Toma''ninah', 'Toma''ninah bermaksud diam sekadar masa membaca "Subhanallah" pada setiap rukun fi''li seperti rukuk, iktidal, sujud, dan duduk antara dua sujud.', 'true_false', null, 'Benar', 'Toma''ninah ialah berhenti seketika (diam dan tenang) sekurang-kurangnya sekadar masa yang cukup untuk membaca "Subhanallah" pada setiap rukun fi''li (rukuk, iktidal, sujud, dan duduk antara dua sujud). Ia merupakan salah satu rukun solat menurut Mazhab Syafie. (Rujukan: Hadis "Musii'' al-Solah" - riwayat Bukhari no. 757; Kitab Fiqh Manhaji)', 'standard', array['solat', 'tomaninah', 'rukun_solat']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 6, 'Solat Fardu & Toma''ninah', 'Perkara yang membatalkan solat termasuk bercakap dengan sengaja, makan, minum, dan melakukan gerakan yang banyak (________ kathirah) secara berturut-turut.', 'fill_blank', null, 'harakah', 'Harakah kathirah (gerakan yang banyak) secara berturut-turut dengan sengaja membatalkan solat. Contohnya melangkah tiga langkah berturut-turut atau menggerakkan tangan berkali-kali secara berterusan. Gerakan kecil yang sedikit (harakah qalilah) seperti menggaru sekali tidak membatalkan solat. (Rujukan: Kitab Fiqh Manhaji, Jilid 1; Kitab al-Majmu'' oleh Imam Nawawi)', 'standard', array['solat', 'batal_solat', 'harakah_kathirah']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 6, 'Solat Fardu & Toma''ninah', 'Seorang musafir yang dalam perjalanan dari Kuala Lumpur ke Johor Bahru ingin menunaikan solat Zohor. Apakah syarat untuk dia melakukan qasar (memendekkan solat)?', 'mcq', array['Jarak perjalanan mesti melebihi 50 km dan berniat qasar', 'Jarak perjalanan mesti melebihi dua marhalah (lebih kurang 81 km) dan berniat qasar ketika takbiratul ihram', 'Sekadar berada di luar kawasan rumah sudah boleh qasar', 'Mesti mendapat izin imam masjid setempat untuk melakukan qasar'], 'Jarak perjalanan mesti melebihi dua marhalah (lebih kurang 81 km) dan berniat qasar ketika takbiratul ihram', 'Menurut Mazhab Syafie, syarat qasar termasuk: (1) perjalanan melebihi dua marhalah (sekitar 81 km/89 km), (2) perjalanan yang harus (bukan untuk maksiat), (3) berniat qasar ketika takbiratul ihram, (4) solat yang boleh diqasar hanya solat empat rakaat (Zohor, Asar, Isyak). Subuh dan Maghrib tidak boleh diqasar. (Rujukan: Hadis riwayat Bukhari no. 1080; Kitab Fiqh Manhaji, Jilid 1)', 'kbat', array['solat', 'qasar', 'musafir', 'fiqh_syafie']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 7, 'Solat Berjemaah & Masbuk/Muafik', 'Apakah hukum solat berjemaah bagi lelaki menurut Mazhab Syafie?', 'mcq', array['Wajib ain', 'Fardu kifayah', 'Sunat muakkad', 'Harus'], 'Sunat muakkad', 'Menurut pendapat muktamad Mazhab Syafie, hukum solat berjemaah bagi lelaki ialah sunat muakkad (sunat yang sangat dituntut). Pendapat ini berbeza dengan mazhab lain yang mengatakan wajib ain atau fardu kifayah. Pahala solat berjemaah adalah 27 kali ganda berbanding solat bersendirian. (Rujukan: Hadis riwayat Bukhari no. 645 dan Muslim no. 650; Kitab Fiqh Manhaji, Jilid 1)', 'standard', array['solat_berjemaah', 'hukum', 'fiqh_syafie']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 7, 'Solat Berjemaah & Masbuk/Muafik', 'Zaid tiba di masjid untuk solat Maghrib dan mendapati imam sedang rukuk pada rakaat kedua. Dia terus takbiratul ihram dan rukuk bersama imam. Berapakah rakaat yang Zaid kira sebagai makmum muafik dan berapa rakaat yang perlu dia tambah selepas imam salam?', 'mcq', array['Muafik 2 rakaat, tambah 1 rakaat', 'Muafik 1 rakaat, tambah 2 rakaat', 'Muafik 3 rakaat, tidak perlu tambah', 'Muafik 2 rakaat, tambah 2 rakaat'], 'Muafik 2 rakaat, tambah 1 rakaat', 'Zaid sempat mengikut imam dari rakaat kedua (sempat rukuk bersama imam pada rakaat kedua). Maka dia mendapat rakaat kedua dan ketiga bersama imam (2 rakaat muafik). Solat Maghrib ada 3 rakaat, jadi selepas imam salam, Zaid perlu bangun dan menambah 1 rakaat lagi untuk menyempurnakan 3 rakaat. Makmum dikira mendapat satu rakaat jika sempat rukuk bersama imam. (Rujukan: Hadis riwayat Bukhari no. 783; Kitab Fiqh Manhaji)', 'kbat', array['solat_berjemaah', 'masbuk', 'muafik', 'maghrib']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 7, 'Solat Berjemaah & Masbuk/Muafik', 'Makmum yang bersin dan membaca "Alhamdulillah" dengan suara kuat semasa solat berjemaah, solatnya menjadi batal.', 'true_false', null, 'Salah', 'Membaca "Alhamdulillah" selepas bersin dalam solat tidak membatalkan solat kerana ia termasuk dalam zikir (mengingati Allah) dan bukan percakapan biasa. Yang membatalkan solat ialah bercakap-cakap (kalam adami) dengan sengaja, iaitu perkataan yang ditujukan kepada manusia. (Rujukan: Hadis Muawiyah bin al-Hakam, riwayat Muslim no. 537; Kitab Fiqh Manhaji)', 'standard', array['solat_berjemaah', 'adab_solat', 'batal_solat']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 7, 'Solat Berjemaah & Masbuk/Muafik', 'Makmum yang sempat mengikuti imam dari awal solat sehingga salam dipanggil makmum ________.', 'fill_blank', null, 'muafik', 'Makmum muafik ialah makmum yang sempat mengikuti imam dari awal solat (takbiratul ihram) atau sekurang-kurangnya sempat mendapat semua rakaat bersama imam. Berbeza dengan makmum masbuk yang tertinggal satu rakaat atau lebih. (Rujukan: Kitab Fiqh Manhaji, Jilid 1; Kitab al-Majmu'' oleh Imam Nawawi)', 'easy', array['solat_berjemaah', 'muafik', 'istilah_fiqh']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 7, 'Solat Berjemaah & Masbuk/Muafik', 'Dalam solat berjemaah, imam terlupa dan bangun untuk rakaat kelima (lebihan) dalam solat Zohor. Apakah tindakan yang sepatutnya dilakukan oleh makmum?', 'mcq', array['Mengikut imam berdiri untuk rakaat kelima kerana makmum wajib mengikut imam', 'Makmum wajib kekal duduk dan bertasbih (membaca Subhanallah) untuk memaklumkan imam tentang kesilapannya', 'Makmum terus salam sendirian dan meninggalkan imam', 'Makmum berdiri bersama imam tetapi tidak membaca apa-apa'], 'Makmum wajib kekal duduk dan bertasbih (membaca Subhanallah) untuk memaklumkan imam tentang kesilapannya', 'Apabila imam melakukan kesilapan seperti menambah rakaat, makmum wajib mengingatkan imam dengan membaca "Subhanallah" (bagi lelaki) atau menepuk belakang tangan (bagi perempuan). Makmum tidak boleh mengikut imam dalam perkara yang diketahui salah. Imam yang sedar kesilapannya wajib kembali duduk dan melakukan sujud sahwi. (Rujukan: Hadis riwayat Bukhari no. 1227 dan Muslim no. 421; Kitab Fiqh Manhaji)', 'kbat', array['solat_berjemaah', 'kesilapan_imam', 'tasbih', 'sujud_sahwi']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 8, 'Puasa Ramadan', 'Apakah perkara yang membatalkan puasa menurut Mazhab Syafie?', 'mcq', array['Berkumur-kumur tanpa sengaja menelan air', 'Memasukkan sesuatu ke dalam rongga badan dengan sengaja dan mengetahui ia membatalkan puasa', 'Bermimpi pada waktu siang', 'Terlupa makan atau minum semasa berpuasa'], 'Memasukkan sesuatu ke dalam rongga badan dengan sengaja dan mengetahui ia membatalkan puasa', 'Perkara yang membatalkan puasa termasuk memasukkan sesuatu ke dalam rongga badan (makan, minum, suntikan ke rongga) dengan sengaja, bersetubuh, dan muntah dengan sengaja. Makan atau minum kerana lupa tidak membatalkan puasa berdasarkan hadis: "Sesiapa yang lupa sedang dia berpuasa lalu dia makan atau minum, hendaklah dia menyempurnakan puasanya." (Rujukan: Hadis riwayat Bukhari no. 1933 dan Muslim no. 1155)', 'standard', array['puasa', 'batal_puasa', 'ramadan']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 8, 'Puasa Ramadan', 'Apakah perbezaan antara fidyah dan kaffarah dalam konteks puasa Ramadan?', 'mcq', array['Tiada perbezaan kerana kedua-duanya bermaksud membayar denda wang', 'Fidyah ialah bayaran ganti bagi orang yang tidak mampu berpuasa manakala kaffarah ialah denda bagi yang sengaja membatalkan puasa tanpa uzur', 'Fidyah lebih berat daripada kaffarah', 'Kaffarah hanya perlu dibayar oleh orang kaya sahaja'], 'Fidyah ialah bayaran ganti bagi orang yang tidak mampu berpuasa manakala kaffarah ialah denda bagi yang sengaja membatalkan puasa tanpa uzur', 'Fidyah ialah memberi makan seorang miskin (satu mud beras atau makanan ruji) bagi setiap hari puasa yang ditinggalkan oleh orang yang tidak mampu berpuasa (sakit kronik, tua uzur). Kaffarah pula ialah denda yang lebih berat bagi yang sengaja membatalkan puasa melalui persetubuhan pada siang Ramadan. Kaffarahnya ialah memerdekakan hamba, atau berpuasa 60 hari berturut-turut, atau memberi makan 60 orang miskin. (Rujukan: Surah al-Baqarah 2:184; Hadis riwayat Bukhari no. 1936)', 'kbat', array['puasa', 'fidyah', 'kaffarah', 'ramadan']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 8, 'Puasa Ramadan', 'Malam Lailatul Qadr hanya berlaku pada malam ke-27 Ramadan sahaja.', 'true_false', null, 'Salah', 'Malam Lailatul Qadr tidak ditetapkan pada satu malam sahaja. Ia berlaku pada salah satu malam ganjil dalam sepuluh malam terakhir Ramadan (malam ke-21, 23, 25, 27, atau 29). Rasulullah SAW bersabda: "Carilah Lailatul Qadr pada malam-malam ganjil daripada sepuluh malam terakhir bulan Ramadan." (Rujukan: Hadis riwayat Bukhari no. 2017; Surah al-Qadr 97:1-5)', 'standard', array['puasa', 'lailatul_qadr', 'ramadan']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 8, 'Puasa Ramadan', 'Golongan yang diberi rukhsah berbuka puasa dan hanya perlu membayar fidyah tanpa perlu qada ialah orang tua yang uzur dan orang sakit yang tidak ada harapan untuk ________.', 'fill_blank', null, 'sembuh', 'Orang tua yang lemah dan orang sakit kronik yang tidak ada harapan untuk sembuh diberi keringanan (rukhsah) untuk tidak berpuasa. Mereka hanya perlu membayar fidyah (memberi makan seorang miskin) bagi setiap hari puasa yang ditinggalkan tanpa perlu mengqadakan puasa tersebut. (Rujukan: Surah al-Baqarah 2:184; Tafsir Ibn Kathir)', 'standard', array['puasa', 'fidyah', 'uzur', 'ramadan']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 8, 'Puasa Ramadan', 'Siti berpuasa Ramadan tetapi pada waktu Zohor, dia terpaksa mengambil ubat melalui mulut kerana sakit yang teruk dan dikhuatiri membahayakan nyawanya. Apakah hukum bagi tindakan Siti?', 'mcq', array['Haram dan berdosa besar kerana sengaja membatalkan puasa', 'Harus berbuka dan wajib mengqada puasa tersebut selepas Ramadan kerana uzur sakit yang membahayakan', 'Puasanya tidak batal kerana makan ubat ketika sakit tidak dikira membatalkan puasa', 'Wajib membayar kaffarah kerana telah membatalkan puasa dengan sengaja'], 'Harus berbuka dan wajib mengqada puasa tersebut selepas Ramadan kerana uzur sakit yang membahayakan', 'Islam memberikan rukhsah (keringanan) kepada orang sakit untuk berbuka puasa jika berpuasa membahayakan nyawa atau memburukkan keadaan sakitnya. Firman Allah: "...maka sesiapa di antara kamu sakit atau dalam perjalanan, maka (hendaklah dia berpuasa) sebilangan hari yang lain." Siti wajib mengqada puasa tersebut selepas sembuh atau selepas Ramadan. (Rujukan: Surah al-Baqarah 2:185; Kitab Fiqh Manhaji)', 'kbat', array['puasa', 'uzur', 'qada', 'ramadan', 'rukhsah']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 9, 'Adab & Akhlak Islamiah', 'Apakah adab utama yang perlu diamalkan ketika berinteraksi dengan jiran yang berlainan agama?', 'mcq', array['Tidak perlu bertegur sapa kerana berlainan agama', 'Berlaku baik, menghormati, tidak menyakiti, dan menjaga hubungan kejiranan', 'Memaksa mereka memeluk Islam', 'Mengelak daripada sebarang interaksi sosial'], 'Berlaku baik, menghormati, tidak menyakiti, dan menjaga hubungan kejiranan', 'Islam mengajar umatnya supaya berbuat baik kepada jiran tanpa mengira agama, bangsa, atau keturunan. Rasulullah SAW bersabda: "Malaikat Jibril sentiasa berpesan kepadaku tentang jiran sehingga aku menyangka jiran itu akan mewarisi harta jirannya." Berbuat baik kepada jiran bukan Muslim adalah sebahagian daripada dakwah bil hal (dakwah melalui perbuatan). (Rujukan: Hadis riwayat Bukhari no. 6014 dan Muslim no. 2625; Surah al-Mumtahanah 60:8)', 'standard', array['adab', 'akhlak', 'jiran', 'hubungan_antara_agama']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 9, 'Adab & Akhlak Islamiah', 'Ahmad menyebarkan berita tentang keburukan rakannya di media sosial tanpa mengesahkan kesahihannya. Apakah dosa yang dilakukan Ahmad menurut perspektif Islam?', 'mcq', array['Ghibah (mengumpat) sahaja', 'Namimah (mengadu domba) sahaja', 'Buhtan (fitnah) kerana menyebarkan berita yang belum disahkan', 'Tidak berdosa kerana ia berlaku di dunia maya, bukan secara bersemuka'], 'Buhtan (fitnah) kerana menyebarkan berita yang belum disahkan', 'Jika berita yang disebarkan itu benar dan diketahui, ia termasuk ghibah (mengumpat). Jika berita itu tidak benar atau belum disahkan, ia termasuk buhtan (fitnah/tuduhan palsu) yang dosanya lebih berat. Rasulullah SAW bersabda: "Jika apa yang kamu katakan tentang saudaramu itu benar, maka kamu telah mengumpatnya. Jika tidak benar, maka kamu telah memfitnahnya." Platform media sosial tidak mengubah hukum - dosa tetap sama. (Rujukan: Hadis riwayat Muslim no. 2589; Surah al-Hujurat 49:12)', 'kbat', array['adab', 'akhlak', 'media_sosial', 'ghibah', 'buhtan', 'fitnah']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 9, 'Adab & Akhlak Islamiah', 'Menurut Islam, memberikan "like" atau "share" kepada kandungan yang mengandungi fitnah atau berita palsu di media sosial tidak berdosa kerana kita bukan penulis asal kandungan tersebut.', 'true_false', null, 'Salah', 'Dalam Islam, menyebarkan fitnah atau berita palsu adalah haram sama ada kita penulis asal atau penyebar. "Like" atau "share" yang membantu penyebaran kandungan batil turut menjadikan kita bersekongkol dalam dosa tersebut. Firman Allah: "Wahai orang-orang yang beriman, jika datang kepadamu orang fasik membawa suatu berita, maka periksalah dengan teliti." Kewajipan tabayyun (mengesahkan) terpakai di semua platform. (Rujukan: Surah al-Hujurat 49:6; Hadis riwayat Muslim tentang larangan menyampaikan setiap yang didengar)', 'kbat', array['adab', 'akhlak', 'media_sosial', 'tabayyun', 'fitnah']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 9, 'Adab & Akhlak Islamiah', 'Sifat mahmudah (terpuji) yang bermaksud bercakap benar dan jujur dalam Islam dipanggil sifat ________.', 'fill_blank', null, 'siddiq', 'Siddiq bermaksud benar dan jujur. Ia merupakan salah satu sifat wajib bagi para rasul dan juga sifat mahmudah yang dituntut ke atas setiap Muslim. Rasulullah SAW bersabda: "Hendaklah kamu sentiasa bersifat jujur kerana kejujuran membawa kepada kebaikan, dan kebaikan membawa ke syurga." (Rujukan: Hadis riwayat Bukhari no. 6094 dan Muslim no. 2607)', 'standard', array['adab', 'akhlak', 'siddiq', 'sifat_mahmudah']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 9, 'Adab & Akhlak Islamiah', 'Apakah adab yang perlu diamalkan ketika menziarahi orang sakit menurut sunnah Rasulullah SAW?', 'mcq', array['Duduk lama di sisi pesakit supaya dia tidak berasa sunyi', 'Memendekkan lawatan, mendoakan kesembuhan, dan tidak menyentuh perkara yang menyedihkan pesakit', 'Memberitahu pesakit tentang semua berita buruk supaya dia bersedia', 'Membawa makanan yang banyak walaupun pesakit tidak selera makan'], 'Memendekkan lawatan, mendoakan kesembuhan, dan tidak menyentuh perkara yang menyedihkan pesakit', 'Sunnah menziarahi orang sakit termasuk: (1) memendekkan lawatan supaya tidak membebankan pesakit, (2) mendoakan kesembuhan dengan doa seperti "Allahumma isyfi ''abdaka, yankal laka ''aduwwan aw yamsyi laka ila solah", (3) bertanya khabar dan memberi semangat, (4) tidak membicarakan perkara yang menyedihkan atau menakutkan pesakit. (Rujukan: Hadis riwayat Bukhari no. 5659; Kitab Riyadh al-Salihin oleh Imam Nawawi)', 'standard', array['adab', 'akhlak', 'ziarah_orang_sakit', 'sunnah']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 10, 'Sirah Nabawiyah', 'Apakah nama peristiwa perpindahan Rasulullah SAW dan umat Islam dari Makkah ke Madinah?', 'mcq', array['Israk dan Mikraj', 'Hijrah', 'Futuh Makkah', 'Baiah Aqabah'], 'Hijrah', 'Hijrah ialah peristiwa perpindahan Rasulullah SAW bersama umat Islam dari Makkah ke Madinah pada tahun 622 Masihi (1 Hijriah). Peristiwa ini menandakan permulaan kalendar Hijriah dan merupakan titik perubahan besar dalam sejarah Islam. (Rujukan: Surah al-Anfal 8:30; Hadis riwayat Bukhari - Kitab al-Hijrah)', 'easy', array['sirah', 'hijrah', 'peristiwa_utama']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 10, 'Sirah Nabawiyah', 'Perang Badar (2 Hijriah) dianggap sebagai "Yawm al-Furqan" (Hari Pembeza). Mengapakah perang ini diberi gelaran tersebut?', 'mcq', array['Kerana jumlah tentera Islam jauh lebih ramai daripada tentera Quraisy', 'Kerana ia merupakan titik yang membezakan antara kebenaran (haq) dan kebatilan (batil) serta mengukuhkan kedudukan Islam di Semenanjung Arab', 'Kerana ia merupakan perang terakhir Rasulullah SAW', 'Kerana hanya seorang sahaja yang syahid dalam perang tersebut'], 'Kerana ia merupakan titik yang membezakan antara kebenaran (haq) dan kebatilan (batil) serta mengukuhkan kedudukan Islam di Semenanjung Arab', 'Perang Badar disebut Yawm al-Furqan kerana ia menjadi pemisah antara kebenaran dan kebatilan. Kemenangan 313 tentera Islam menentang kira-kira 1000 tentera Quraisy membuktikan pertolongan Allah dan mengukuhkan kedudukan politik dan ketenteraan Islam di Madinah. Al-Quran menyebut: "Jika kamu beriman kepada Allah dan apa yang Kami turunkan kepada hamba Kami pada Hari al-Furqan, iaitu hari bertemunya dua pasukan." (Rujukan: Surah al-Anfal 8:41; Sirah Ibn Hisyam)', 'kbat', array['sirah', 'perang_badar', 'yawm_al_furqan']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 10, 'Sirah Nabawiyah', 'Perjanjian Hudaibiyyah pada awalnya dilihat sebagai kerugian bagi umat Islam tetapi sebenarnya membawa kemenangan besar dari sudut diplomasi dan penyebaran Islam.', 'true_false', null, 'Benar', 'Perjanjian Hudaibiyyah (6 Hijriah) pada zahirnya kelihatan merugikan umat Islam kerana beberapa syaratnya berat sebelah. Namun, ia sebenarnya membuka ruang dakwah yang luas kerana gencatan senjata membolehkan Rasulullah SAW menghantar surat dakwah kepada raja-raja dan penyebaran Islam berlaku dengan pesat. Al-Quran menyebutnya sebagai "al-Fath al-Mubin" (kemenangan yang nyata). (Rujukan: Surah al-Fath 48:1; Sirah Ibn Hisyam; Hadis riwayat Bukhari - Kitab al-Shurut)', 'standard', array['sirah', 'hudaibiyyah', 'diplomasi', 'perjanjian']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 10, 'Sirah Nabawiyah', 'Rasulullah SAW mengikat tali persaudaraan (muakhah) antara golongan Muhajirin dan ________ selepas tiba di Madinah.', 'fill_blank', null, 'Ansar', 'Selepas Hijrah ke Madinah, Rasulullah SAW mengadakan ikatan persaudaraan (muakhah) antara golongan Muhajirin (pendatang dari Makkah) dan Ansar (penduduk asal Madinah yang menolong). Ansar berkongsi harta, rumah, dan perniagaan mereka dengan saudara Muhajirin. Ini merupakan salah satu langkah diplomatik terawal Rasulullah SAW untuk membina masyarakat Islam yang bersatu. (Rujukan: Hadis riwayat Bukhari no. 3937; Sirah Ibn Hisyam)', 'standard', array['sirah', 'muakhah', 'muhajirin', 'ansar', 'madinah']);
insert into pafakafa_questions (level, chapter, chapter_title, question_text, question_type, options, correct_answer, explanation, difficulty, tags)
values ('f3', 10, 'Sirah Nabawiyah', 'Apakah pengajaran utama yang boleh diambil daripada peristiwa pembukaan semula Kota Makkah (Futuh Makkah) pada tahun 8 Hijriah dari aspek kepimpinan Rasulullah SAW?', 'mcq', array['Pemimpin perlu menunjukkan kekuatan tentera untuk menakutkan musuh', 'Keagungan Islam terletak pada semangat membalas dendam terhadap musuh', 'Rasulullah SAW menunjukkan sifat pemaaf dan belas kasihan walaupun berkuasa penuh untuk membalas dendam terhadap penduduk Makkah', 'Pembukaan Makkah hanya bertujuan untuk menguasai ekonomi perdagangan'], 'Rasulullah SAW menunjukkan sifat pemaaf dan belas kasihan walaupun berkuasa penuh untuk membalas dendam terhadap penduduk Makkah', 'Semasa pembukaan Makkah, Rasulullah SAW mengampunkan penduduk Makkah yang selama ini menzalimi umat Islam. Baginda bersabda: "Pergilah kamu, kamu semua bebas." Ini menunjukkan sifat kepimpinan yang agung - mengutamakan perdamaian, kemaafan, dan belas kasihan walaupun berada dalam posisi berkuasa. Tindakan ini menyebabkan ramai penduduk Makkah memeluk Islam secara sukarela. (Rujukan: Sirah Ibn Hisyam; Hadis Futuh Makkah riwayat Bukhari; Surah al-Anbiya'' 21:107)', 'kbat', array['sirah', 'futuh_makkah', 'kepimpinan', 'pengajaran']);
